    code: "// NAME: Transparent Lava Bubbles\nuniform float timeScale; // @default 1.0\nuniform vec3 lavaColor; // @default 1.0,0.3,0.0\nuniform float blackThreshold; // @min 0.0 @max 1.0 @default 0.0\nuniform float morphIntensity; // @min 0.0 @max 5.0 @default 1.0\nuniform float refraction; // @min 0.0 @max 0.5 @default 0.1\nuniform float luminosity; // @min 0.0 @max 3.0 @default 1.0\nuniform float contrast; // @min 0.0 @max 3.0 @default 1.0\nuniform float bubbleOpacity; // @min 0.0 @max 1.0 @default 0.4\n\nfloat smin(float a, float b, float k) {\n    float h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0);\n    return mix(b, a, h) - k * h * (1.0 - h);\n}\n\nfloat map(vec3 p, float t, float lum) {\n    float d = p.y + 3.0; \n    d = smin(d, 3.0 - p.y, 1.0); \n    \n    vec3 q = p;\n    q.x = mod(q.x + 2.5, 5.0) - 2.5;\n    \n    for(int i = 0; i < 6; i++) {\n        float fi = float(i);\n        vec3 pos = vec3(\n            sin(t * 0.7 + fi * 2.1) * 1.2,\n            sin(t * 0.4 + fi * 1.7) * 2.8,\n            cos(t * 0.6 + fi * 1.3) * 0.8\n        );\n        float r = 0.6 + lum * morphIntensity * 0.3 + sin(fi) * 0.2;\n        d = smin(d, length(q - pos) - r, 1.2);\n    }\n    return d;\n}\n\nvec3 calcNormal(vec3 p, float t, float lum) {\n    vec2 e = vec2(0.01, 0.0);\n    return normalize(vec3(\n        map(p+e.xyy, t, lum) - map(p-e.xyy, t, lum),\n        map(p+e.yxy, t, lum) - map(p-e.yxy, t, lum),\n        map(p+e.yyx, t, lum) - map(p-e.yyx, t, lum)\n    ));\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 bg = texture2D(tex, uv);\n    float bgLum = dot(bg.rgb, vec3(0.299, 0.587, 0.114));\n    \n    vec3 finalColor = bg.rgb;\n    \n    if (bgLum < blackThreshold) {\n        finalColor = vec3(0.0);\n    } else {\n        vec2 p_uv = (uv - 0.5) * 2.0;\n        p_uv.x *= resolution.x / resolution.y;\n        \n        vec3 ray = normalize(vec3(p_uv, 1.0));\n        vec3 camPos = vec3(0.0, 0.0, -4.0);\n        vec3 pos = camPos;\n        \n        float t = time * timeScale;\n        float dist = 0.0;\n        \n        for(int i = 0; i < 60; i++) {\n            dist = map(pos, t, bgLum);\n            if(dist < 0.005 || pos.z > 10.0) break;\n            pos += ray * dist;\n        }\n        \n        if (dist < 0.005) {\n            vec3 n = calcNormal(pos, t, bgLum);\n            vec3 l = normalize(vec3(0.5, 1.0, -1.0));\n            \n            vec2 distortedUV = uv + n.xy * refraction;\n            vec3 distortedBg = texture2D(tex, distortedUV).rgb;\n            \n            float spec = pow(max(dot(reflect(-l, n), -ray), 0.0), 32.0);\n            float fresnel = pow(1.0 - max(dot(n, -ray), 0.0), 3.0);\n            \n            float mixFactor = clamp(bubbleOpacity + fresnel * 0.6, 0.0, 1.0);\n            vec3 col = mix(distortedBg, lavaColor, mixFactor);\n            col += spec * 0.8;\n            \n            float distFromCam = length(pos - camPos);\n            float alpha = 1.0 - smoothstep(4.0, 12.0, distFromCam);\n            \n            finalColor = mix(bg.rgb, col, alpha);\n        }\n    }\n    \n    finalColor = (finalColor - 0.5) * contrast + 0.5;\n    finalColor *= luminosity;\n    \n    return vec4(clamp(finalColor, 0.0, 1.0), 1.0);\n}",
