    group: "Imported",
    description: "Imported from shared/user project as a sculpture preset.",
    code: "// NAME: Reverse Clones Diff\nuniform float depth; // @min 0.0 @max 0.2 @default 0.05\nuniform float zoomSpeed; // @min 0.1 @max 3.0 @default 0.5\nuniform float scaleFactor; // @min 1.1 @max 3.0 @default 1.5\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.1\nuniform float edgeIntensity; // @min 0.0 @max 5.0 @default 1.5\nuniform vec3 tint; // @default 1.0,1.0,1.0\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 sumDiff = vec4(0.0);\n    vec4 prevLayer = vec4(0.0);\n    \n    // Fractional time for the infinite loop\n    float t = fract(time * zoomSpeed);\n    \n    // Loop to create multiple clones\n    for (int i = 0; i < 6; i++) {\n        // Reversed zoom: subtract t instead of adding it\n        float currentScale = pow(scaleFactor, float(i) - t);\n        \n        vec2 centeredUV = uv - 0.5;\n        vec2 cloneUV = centeredUV * currentScale + 0.5;\n        \n        // Soft edge mask to completely hide the hard borders of the image\n        vec2 edgeDist = abs(cloneUV - 0.5) * 2.0;\n        float edgeMask = smoothstep(1.0, 0.8, max(edgeDist.x, edgeDist.y));\n        \n        // Base sample for depth/luma\n        vec4 base = texture2D(tex, cloneUV);\n        float luma = dot(base.rgb, vec3(0.299, 0.587, 0.114));\n        \n        // 3D Parallax offset\n        vec2 offset = centeredUV * luma * depth * currentScale;\n        vec4 layer3D = texture2D(tex, cloneUV - offset);\n        \n        // Fake edge highlight with customizable intensity\n        float edge = length(layer3D.rgb - base.rgb);\n        vec3 layerColor = layer3D.rgb + vec3(edge * edgeIntensity);\n        \n        float alpha = max(layer3D.a, luma);\n        \n        // Apply mask without fading the layer itself\n        vec4 currentLayer = vec4(layerColor * alpha, alpha) * edgeMask;\n        \n        // Sum the absolute difference between consecutive layers, fading the differences to make it seamless\n        if (i > 0) {\n            float fade = 1.0;\n            // Inverted fade logic for the reversed zoom direction\n            if (i == 1) fade = 1.0 - t;\n            if (i == 5) fade = t;\n            \n            sumDiff += abs(currentLayer - prevLayer) * fade;\n        }\n        \n        prevLayer = currentLayer;\n    }\n    \n    // Original background for thresholding mask\n    vec4 source = texture2D(tex, uv);\n    float sourceLuma = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    float threshMask = smoothstep(max(0.0, threshold - 0.05), threshold + 0.01, sourceLuma);\n    \n    // Show only the summed differences, masked by the threshold and tinted\n    return clamp(sumDiff * threshMask * vec4(tint, 1.0), 0.0, 1.0);\n}",
