    description: "Imported from shared/user project as a sculpture preset.",
    code: "// NAME: Edge Disco Rays\nuniform float pixelSize; // @min 2.0 @max 64.0 @default 16.0\nuniform float speed; // @min 0.0 @max 5.0 @default 2.0\nuniform vec3 waterColor; // @default 0.1,0.4,0.9\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float reflectivity; // @min 0.0 @max 5.0 @default 1.5\nuniform float rayIntensity; // @min 0.0 @max 5.0 @default 1.0\nuniform float contrast; // @min 0.0 @max 3.0 @default 1.2\nuniform float luminosity; // @min 0.0 @max 3.0 @default 1.0\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    \n    // Calculate color intensity of the image\n    float intensity = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    \n    // Grid affected by previous state, multiplied by intensity, then add 4\n    vec2 baseGrid = resolution / pixelSize;\n    vec2 grid = baseGrid * intensity + 4.0;\n    \n    vec2 cellUv = floor(uv * grid) / grid;\n    \n    float t = time * speed;\n    \n    // Simulate water depth/flow using layered noise\n    float n = node_noise(cellUv * 5.0 + vec2(t * 0.2, t * 0.5));\n    n += node_noise(cellUv * 10.0 - vec2(t * 0.3, 0.0)) * 0.5;\n    \n    // Quantize to simulate discrete CA states\n    float states = 4.0;\n    float caState = floor(n * states) / states;\n    \n    // Base colorized state\n    vec3 colorized = mix(source.rgb, waterColor * 1.5, caState * 0.7);\n    \n    // Create a pseudo-normal for the facet to make it reflective\n    vec2 localUv = fract(uv * grid);\n    vec2 centerDist = localUv - 0.5;\n    \n    // Facet tilt based on noise to give each cell a unique reflection angle\n    vec2 tilt = vec2(node_noise(cellUv * 20.0), node_noise(cellUv * 20.0 + 5.0)) * 2.0 - 1.0;\n    vec3 normal = normalize(vec3(tilt * 0.8 + centerDist * 0.2, 1.0));\n    \n    // Moving light source for dynamic reflections\n    vec3 lightPos = vec3(sin(t * 0.5), cos(t * 0.5), 1.0);\n    vec3 lightDir = normalize(lightPos - vec3(uv * 2.0 - 1.0, 0.0));\n    \n    // Specular highlight (Blinn-Phong)\n    vec3 viewDir = vec3(0.0, 0.0, 1.0);\n    vec3 halfVector = normalize(lightDir + viewDir);\n    float spec = pow(max(dot(normal, halfVector), 0.0), 16.0) * reflectivity;\n    \n    // Add bright specular reflection\n    colorized += vec3(spec);\n    \n    // Disco ball reflective rays\n    vec2 centered = uv - 0.5;\n    float angle = atan(centered.y, centered.x);\n    float radius = length(centered);\n    float rays = 0.0;\n    float rayT = t * 0.3;\n    \n    // Blur the center of the rays by lowering the exponent near the center\n    float blurFactor = smoothstep(0.1, 0.5, radius);\n    float exp1 = mix(2.0, 40.0, blurFactor);\n    float exp2 = mix(2.0, 50.0, blurFactor);\n    float exp3 = mix(2.0, 60.0, blurFactor);\n    \n    rays += pow(sin(angle * 14.0 + rayT) * 0.5 + 0.5, exp1);\n    rays += pow(sin(angle * 9.0 - rayT * 1.5) * 0.5 + 0.5, exp2);\n    rays += pow(sin(angle * 21.0 + rayT * 0.8) * 0.5 + 0.5, exp3);\n    \n    // Fade out the center so rays only appear at the edge\n    rays *= smoothstep(0.15, 0.45, radius);\n    \n    colorized += vec3(rays * rayIntensity);\n    \n    // Add subtle grid lines for CA visualization (darker borders for depth)\n    float border = step(0.05, localUv.x) * step(0.05, localUv.y);\n    colorized *= mix(0.4, 1.0, border);\n    \n    // Mask out pixels below the threshold\n    float mask = step(threshold, intensity);\n    vec3 finalColor = mix(source.rgb, colorized, mask);\n    \n    // Apply contrast\n    finalColor = (finalColor - 0.5) * contrast + 0.5;\n    \n    // Apply luminosity\n    finalColor *= luminosity;\n    \n    finalColor = clamp(finalColor, 0.0, 1.0);\n    \n    return vec4(finalColor, source.a);\n}",
