    code: "// NAME: Mirrored Glowing Radial Dots\nuniform float scale; // @min 5.0 @max 100.0 @default 25.0\nuniform float centerScale; // @min 0.0 @max 3.0 @default 1.0\nuniform float thickness; // @min 0.01 @max 1.0 @default 0.6\nuniform float noiseThickness; // @min 0.0 @max 1.0 @default 0.5\nuniform float noiseAnimSpeed; // @min 0.0 @max 5.0 @default 1.0\nuniform float speed; // @min 0.0 @max 5.0 @default 1.0\nuniform float zoomSpeed; // @min 0.0 @max 5.0 @default 1.0\nuniform float palette; // @min 0.0 @max 1.0 @default 0.5\nuniform float morphAmount; // @min 0.0 @max 1.0 @default 0.3\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float mandalaGrid; // @min 1.0 @max 10.0 @default 2.0\nuniform float glow; // @min 0.0 @max 5.0 @default 2.5\nuniform float centerX; // @min 0.0 @max 1.0 @default 0.5\nuniform float centerY; // @min 0.0 @max 1.0 @default 0.5\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec2 center = vec2(centerX, centerY);\n    \n    // Sample the original image with unmodified UVs\n    vec4 orig = texture2D(tex, uv);\n    \n    // Calculate luminosity of the original image\n    float origInt = dot(orig.rgb, vec3(0.299, 0.587, 0.114));\n    \n    // If luminosity is below threshold, return the original image untouched\n    if (origInt <= threshold) return orig;\n\n    // Create a symmetric UV specifically for the shader effect\n    vec2 symUV = uv;\n    if (symUV.x > center.x) {\n        symUV.x = center.x - (symUV.x - center.x);\n    }\n\n    vec2 px = 1.0 / resolution;\n    vec4 n = texture2D(tex, uv + vec2(0.0, px.y));\n    vec4 s = texture2D(tex, uv + vec2(0.0, -px.y));\n    vec4 e = texture2D(tex, uv + vec2(px.x, 0.0));\n    vec4 w = texture2D(tex, uv + vec2(-px.x, 0.0));\n    vec4 src = clamp(orig, min(min(n, s), min(e, w)), max(max(n, s), max(e, w)));\n\n    float morphInt = dot(1.0 - src.rgb, vec3(0.299, 0.587, 0.114));\n    \n    // Apply morphing to the symmetric UV\n    vec2 dUV = symUV;\n    dUV.y -= morphInt * morphAmount;\n    dUV.x += (symUV.x - center.x) * 2.0 * morphInt * morphAmount * 0.2;\n    \n    vec2 p = dUV - center;\n    p.x *= resolution.x / resolution.y;\n    \n    float r = max(length(p), 0.001);\n    float a = atan(p.y, p.x);\n    float logR = log(r) - time * zoomSpeed;\n    \n    float gridInt = max(1.0, floor(mandalaGrid));\n    vec2 baseUV = vec2((a / 6.2831853) * gridInt, logR * centerScale);\n    \n    vec2 scaledUV = baseUV * scale;\n    vec2 grid = fract(scaledUV) - 0.5;\n    vec2 cellId = floor(scaledUV);\n    \n    float dist = length(grid);\n    float aa = 0.02 + 0.1 * smoothstep(0.5, 0.0, r);\n    \n    // Circular gradient noise blob to modulate thickness\n    float globalNoise = node_noise(cellId * 0.15 + time * noiseAnimSpeed);\n    float currentThickness = thickness * 0.5 + globalNoise * noiseThickness * 0.5;\n    \n    float circle = smoothstep(currentThickness + aa, currentThickness - aa, dist);\n    \n    vec3 col1 = vec3(1.0, 0.2, 0.5);\n    vec3 col2 = vec3(0.1, 0.8, 1.0);\n    vec3 col3 = vec3(1.0, 0.9, 0.1);\n    \n    float t = fract(cellId.x * 0.1 + cellId.y * 0.1 - time * speed + palette);\n    vec3 dotColor = mix(col1, col2, smoothstep(0.0, 0.5, t));\n    dotColor = mix(dotColor, col3, smoothstep(0.5, 1.0, t));\n    \n    vec3 finalColor = dotColor * circle * glow;\n    \n    // Blend the symmetric effect over the unmodified original image\n    return vec4(mix(orig.rgb, finalColor, circle), orig.a);\n}",
