    code: "// NAME: Tentacle Spine Animated Mandala\nuniform float scale; // @min 5.0 @max 100.0 @default 25.0\nuniform float thickness; // @min 0.01 @max 0.4 @default 0.15\nuniform float speed; // @min 0.0 @max 5.0 @default 1.0\nuniform vec3 mazeColor; // @default 1.0,1.0,1.0\nuniform float morphAmount; // @min 0.0 @max 1.0 @default 0.3\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float mandalaGrid; // @min 1.0 @max 10.0 @default 2.0\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    float intensity = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    \n    if (intensity <= threshold) {\n        return source;\n    }\n    \n    vec2 distortedUV = uv;\n    distortedUV.y -= intensity * morphAmount;\n    distortedUV.x += (uv.x - 0.5) * 2.0 * intensity * morphAmount * 0.2;\n    \n    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);\n    vec2 baseUV = distortedUV * aspect;\n    \n    // Macro grid for random mandala sections, moving over time\n    vec2 macroUV = baseUV * mandalaGrid;\n    macroUV.x += time * speed * 0.1;\n    macroUV.y += time * speed * 0.15;\n    \n    vec2 macroID = floor(macroUV);\n    vec2 macroGV = fract(macroUV) - 0.5;\n    \n    // Randomize kaleidoscope folds per section (4, 6, 8, or 10 folds)\n    float rndFolds = node_rand(macroID);\n    float folds = 4.0 + floor(rndFolds * 4.0) * 2.0;\n    \n    // Kaleidoscope polar folding\n    float r = length(macroGV);\n    float a = atan(macroGV.y, macroGV.x);\n    float sector = 6.2831853 / folds;\n    a = mod(a, sector);\n    a = abs(a - sector / 2.0);\n    vec2 foldedUV = r * vec2(cos(a), sin(a));\n    \n    // Apply Truchet scale and animation to the folded space\n    vec2 p = foldedUV * scale;\n    p.y += time * speed;\n    p.x += time * speed * 0.5;\n    \n    vec2 id = floor(p);\n    vec2 gv = fract(p) - 0.5;\n    \n    float rnd = node_rand(id);\n    float flip = (rnd < 0.5) ? -1.0 : 1.0;\n    gv.x *= flip;\n    \n    vec2 c1 = vec2(-0.5, -0.5);\n    vec2 c2 = vec2(0.5, 0.5);\n    float d1 = length(gv - c1);\n    float d2 = length(gv - c2);\n    \n    float dist1 = abs(d1 - 0.5);\n    float dist2 = abs(d2 - 0.5);\n    float dist = min(dist1, dist2);\n    \n    float currentThickness = thickness * (0.5 + intensity * 1.0);\n    \n    // HD Anti-aliasing based on resolution and scale\n    float aa = (scale * mandalaGrid) / resolution.y * 1.5;\n    \n    float profile = smoothstep(currentThickness, 0.0, dist);\n    float mask = smoothstep(currentThickness + aa, currentThickness - aa, dist);\n    \n    // Calculate continuous 3D Normal, correcting for the flipped cell\n    vec2 dir = (dist1 < dist2) ? (gv - c1) / d1 * sign(d1 - 0.5) : (gv - c2) / d2 * sign(d2 - 0.5);\n    dir.x *= flip;\n    \n    // Spherical bump mapping for cohesive 3D look\n    vec3 N = normalize(vec3(dir * sin(profile * 1.570796) * 1.5, cos(profile * 1.570796)));\n    \n    vec3 V = vec3(0.0, 0.0, 1.0);\n    vec3 L = normalize(vec3(0.5, 0.8, 1.0));\n    vec3 R = reflect(-V, N);\n    \n    float diff = max(dot(N, L), 0.0);\n    float spec = pow(max(dot(R, L), 0.0), 50.0);\n    float fresnel = pow(1.0 - max(dot(N, V), 0.0), 3.0);\n    \n    vec2 refUV = fract(uv + N.xy * 0.2);\n    vec3 env = texture2D(tex, refUV).rgb;\n    \n    vec3 oily = 0.5 + 0.5 * cos(vec3(0.0, 2.0, 4.0) + N.x * 3.0 + N.y * 4.0 + time);\n    \n    // Color animation expanding from the spine (dist = 0) of the tentacle outwards\n    float normalizedDist = dist / max(currentThickness, 0.001);\n    vec3 waveColor = 0.5 + 0.5 * cos(vec3(0.0, 2.0, 4.0) + normalizedDist * 15.0 - time * 8.0);\n    vec3 currentMazeColor = mazeColor * waveColor;\n    \n    vec3 blobColor = mix(env * currentMazeColor, oily, fresnel * 0.7) * (diff * 0.8 + 0.2) + spec * 1.2;\n    \n    float shadow = smoothstep(currentThickness * 2.5, currentThickness, dist) * 0.7;\n    \n    vec3 finalColor = mix(source.rgb * (1.0 - shadow), blobColor, mask);\n    \n    return vec4(finalColor, source.a);\n}",
