    code: "// NAME: Fluid Color Shadow Morph Maze\nuniform float scale; // @min 5.0 @max 50.0 @default 20.0\nuniform float heightZ; // @min 0.0 @max 0.2 @default 0.1\nuniform float colorShift; // @min 0.0 @max 5.0 @default 1.0\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float lineWidth; // @min 0.01 @max 0.51 @default 0.51\nuniform float glossiness; // @min 10.0 @max 100.0 @default 50.0\nuniform float specular; // @min 0.0 @max 2.0 @default 1.0\nuniform vec3 glowColor; // @default 0.0,1.0,1.0\nuniform float glowSpeed; // @min 0.0 @max 10.0 @default 5.0\nuniform float morphAmount; // @min 0.0 @max 1.0 @default 0.5\nuniform float speed; // @min 0.1 @max 3.0 @default 0.5\nuniform vec3 tint; // @default 0.5,0.7,1.0\n\nfloat getMazeHeight(vec2 st) {\n    vec2 id = floor(st);\n    vec2 gv = fract(st) - 0.5;\n    if (node_rand(id) < 0.5) {\n        gv.x *= -1.0;\n    }\n    \n    float d1 = length(gv - vec2(-0.5, -0.5));\n    float d2 = length(gv - vec2(0.5, 0.5));\n    float d = min(abs(d1 - 0.5), abs(d2 - 0.5));\n    \n    float h = 1.0 - (d / max(lineWidth, 0.001));\n    return max(h, 0.0);\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    \n    float brightness = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    float mask = smoothstep(threshold - 0.05, threshold + 0.05, brightness) * source.a;\n    \n    if (mask <= 0.0) {\n        return source;\n    }\n\n    vec2 st = uv * scale;\n    st.x *= resolution.x / resolution.y;\n\n    vec2 dir = (uv - 0.5) * heightZ;\n    \n    float hitZ = 1.0;\n    vec2 hitSt = st;\n    \n    for(int i = 0; i < 40; i++) {\n        float f = float(i) / 39.0;\n        vec2 offsetSt = st - dir * f * scale;\n        float h = getMazeHeight(offsetSt);\n        \n        if (h > (1.0 - f)) {\n            hitZ = f;\n            hitSt = offsetSt;\n            break;\n        }\n    }\n\n    vec3 finalColor = source.rgb;\n    \n    float shadowH = getMazeHeight(st - dir * scale);\n    vec3 shadowColor = source.rgb;\n    if (shadowH > 0.0) {\n        shadowColor *= mix(1.0, 0.3, shadowH);\n    }\n    \n    if (hitZ < 1.0) {\n        // Fluid-like domain warping for maze color\n        vec2 q = hitSt * 0.5;\n        float t = time * speed;\n        float w = 0.0;\n        \n        for (int i = 0; i < 4; i++) {\n            float c = cos(0.73);\n            float s = sin(0.73);\n            q = mat2(c, -s, s, c) * q * 1.4;\n            q += vec2(sin(q.y + t), cos(q.x - t)) * 0.6;\n            w += sin(q.x + q.y);\n        }\n        \n        vec3 mazeCol = 0.5 + 0.5 * cos(w * 1.5 + tint * colorShift * 5.0 + vec3(0.0, 2.0, 4.0));\n        \n        vec2 eps = vec2(0.02, 0.0);\n        float hx = getMazeHeight(hitSt + eps.xy) - getMazeHeight(hitSt - eps.xy);\n        float hy = getMazeHeight(hitSt + eps.yx) - getMazeHeight(hitSt - eps.yx);\n        vec3 normal = normalize(vec3(-hx, -hy, 0.2));\n        \n        vec3 lightRight = normalize(vec3(1.0, 0.5, 0.8));\n        vec3 lightLeft = normalize(vec3(-1.0, 0.5, 0.8));\n        vec3 viewDir = normalize(vec3(0.0, 0.0, 1.0));\n        \n        float diffRight = max(dot(normal, lightRight), 0.0);\n        float diffLeft = max(dot(normal, lightLeft), 0.0);\n        \n        vec3 halfRight = normalize(lightRight + viewDir);\n        vec3 halfLeft = normalize(lightLeft + viewDir);\n        \n        float specR = pow(max(dot(normal, halfRight), 0.0), glossiness);\n        float specL = pow(max(dot(normal, halfLeft), 0.0), glossiness);\n        \n        vec3 colorRight = vec3(1.0, 0.6, 0.3) * diffRight + vec3(1.0) * specR * specular;\n        vec3 colorLeft = vec3(0.3, 0.6, 1.0) * diffLeft + vec3(1.0) * specL * specular;\n        \n        vec3 lighting = colorRight + colorLeft + vec3(0.3);\n        \n        float shade = 1.0 - hitZ * 0.8;\n        vec3 surfaceColor = mix(source.rgb, mazeCol * lighting * shade, 0.95);\n        \n        float h_hit = getMazeHeight(hitSt);\n        float topMask = smoothstep(0.85, 1.0, h_hit);\n        \n        float movingPulse = sin(uv.x * 10.0 + uv.y * 10.0 - time * glowSpeed) * 0.5 + 0.5;\n        movingPulse = pow(movingPulse, 4.0);\n        \n        vec3 glow = glowColor * topMask * movingPulse * 2.5;\n        surfaceColor += glow;\n        \n        finalColor = mix(shadowColor, surfaceColor, morphAmount);\n    } else {\n        finalColor = shadowColor;\n    }\n\n    finalColor = mix(source.rgb, finalColor, mask);\n\n    return vec4(finalColor, source.a);\n}",
