    code: "// NAME: Dark Illuminated Grid Inverted Center\nuniform float gridScale; // @min 1.0 @max 100.0 @default 20.0\nuniform float xDensity; // @min 1.0 @max 10.0 @default 1.0\nuniform float yDensity; // @min 1.0 @max 10.0 @default 3.0\nuniform float gridThickness; // @min 0.01 @max 0.5 @default 0.05\nuniform vec3 gridColor; // @default 1.0,1.0,1.0\nuniform float morphIntensity; // @min -0.5 @max 0.5 @default 0.1\nuniform float centerMorph; // @min 0.0 @max 1.0 @default 0.5\nuniform float edgeScaleDown; // @min 0.0 @max 5.0 @default 1.5\nuniform float offsetX; // @min -1.0 @max 1.0 @default 0.0\nuniform float offsetY; // @min -1.0 @max 1.0 @default 0.0\nuniform float speedX; // @min -2.0 @max 2.0 @default 0.2\nuniform float speedY; // @min -2.0 @max 2.0 @default 0.2\nuniform float glowIntensity; // @min 0.0 @max 5.0 @default 1.5\nuniform float baseDarkness; // @min 0.0 @max 1.0 @default 0.15\nuniform float illumination; // @min 0.0 @max 5.0 @default 2.5\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    \n    // Calculate intensity of the INVERTED image to drive the morph\n    vec3 invertedRGB = 1.0 - source.rgb;\n    float morphAmountCalc = dot(invertedRGB, vec3(0.299, 0.587, 0.114));\n    \n    // Define the center of the bulge/shrink effect\n    vec2 centerPos = vec2(0.5 + offsetX, 0.5 + offsetY);\n    vec2 centeredUV = uv - centerPos;\n    float dist = length(centeredUV);\n    \n    // Inverted center scale: Increase UV scale near the center to make the grid appear smaller\n    // Modulated by the alpha channel of the image\n    float centerFactor = 1.0 + (centerMorph * 2.0) * (1.0 - smoothstep(0.0, 0.6, dist)) * source.a;\n    \n    // Increase UV scale near the edges to make the grid appear smaller (scale down)\n    float edgeFactor = 1.0 + edgeScaleDown * smoothstep(0.3, 0.8, dist);\n    \n    // Combine scaling factors\n    float scaleFactor = centerFactor * edgeFactor;\n    vec2 bulgedUV = centeredUV * scaleFactor + centerPos;\n    \n    // Morph UV based on the inverted intensity logic\n    vec2 morphedUV = bulgedUV;\n    morphedUV.y -= morphAmountCalc * morphIntensity;\n    morphedUV.x += (bulgedUV.x - centerPos.x) * 2.0 * morphAmountCalc * morphIntensity * 0.2;\n    \n    // Apply time-based animation to move the grid\n    morphedUV += vec2(time * speedX, time * speedY);\n    \n    // Generate dense grid based on morphed UV\n    vec2 scaledUV = morphedUV * vec2(gridScale * xDensity, gridScale * yDensity);\n    vec2 gridUV = fract(scaledUV);\n    vec2 cellID = floor(scaledUV);\n    \n    // Distance to the nearest grid line\n    vec2 distToLine = min(gridUV, 1.0 - gridUV);\n    \n    // Core lines\n    float lineX = smoothstep(gridThickness, gridThickness * 0.2, distToLine.x);\n    float lineY = smoothstep(gridThickness, gridThickness * 0.2, distToLine.y);\n    float coreLine = max(lineX, lineY);\n    \n    // Glow effect\n    float glowX = (gridThickness * 0.3) / (distToLine.x + 0.001);\n    float glowY = (gridThickness * 0.3) / (distToLine.y + 0.001);\n    float glow = max(glowX, glowY) * glowIntensity;\n    \n    // Random edge trails using noise\n    float trailNoise = node_noise(cellID * 0.2 - vec2(time * 3.0, time * 4.0));\n    float trail = smoothstep(0.2, 0.7, trailNoise);\n    \n    // Combine core, glow, and trails\n    float finalGrid = (coreLine + glow) * (0.4 + trail * 1.6);\n    finalGrid = clamp(finalGrid, 0.0, 1.0);\n    \n    // Determine if the pixel is non-black\n    float isNonBlack = step(0.01, length(source.rgb));\n    \n    // Darken the original image\n    vec3 baseColor = source.rgb * baseDarkness;\n    \n    // Illuminate the original image using the grid's intensity\n    vec3 illuminatedColor = source.rgb * finalGrid * illumination;\n    \n    // Add the grid's own color on top\n    vec3 gridOverlay = gridColor * finalGrid * (1.0 + glow) * 0.5;\n    \n    // Combine to create the final illuminated effect\n    vec3 finalColor = (baseColor + illuminatedColor + gridOverlay) * isNonBlack;\n    \n    return vec4(finalColor, source.a);\n}",
