    code: "// NAME: Precise 3 Target Eyes with Saccade Blink\nuniform float greenThreshold; // @min -0.5 @max 0.5 @default 0.05\nuniform vec3 irisColor; // @default 0.415,0.627,0.827\nuniform float pupilSize; // @min 0.05 @max 0.5 @default 0.22\nuniform float irisSize; // @min 0.1 @max 0.8 @default 0.50\nuniform float lightIntensity; // @min 0.0 @max 3.0 @default 1.17\n\nuniform float eye1X; // @min 0.0 @max 1.0 @default 0.60\nuniform float eye1Y; // @min 0.0 @max 1.0 @default 0.50\nuniform float eye2X; // @min 0.0 @max 1.0 @default 0.40\nuniform float eye2Y; // @min 0.0 @max 1.0 @default 0.50\nuniform float eye3X; // @min 0.0 @max 1.0 @default 0.50\nuniform float eye3Y; // @min 0.0 @max 1.0 @default 0.65\n\nuniform bool lookAround; // @default true\nuniform float lookAroundSpeed; // @min 0.1 @max 5.0 @default 0.74\nuniform bool epilepsyMode; // @default false\nuniform bool independentEyes; // @default false\n\nuniform float targetX; // @min 0.0 @max 1.0 @default 0.50\nuniform float targetY; // @min 0.0 @max 1.0 @default 0.50\nuniform float targetZ; // @min 0.1 @max 5.0 @default 0.50\nuniform float eyeRadius; // @min 0.01 @max 0.5 @default 0.06\n\nuniform bool enableBlink; // @default true\nuniform vec3 blinkColor; // @default 0.15,0.1,0.1\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n\n    float greenness = source.g - max(source.r, source.b);\n    float mask = smoothstep(greenThreshold, greenThreshold + 0.1, greenness);\n\n    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);\n    vec2 uvAspect = uv * aspect;\n\n    vec2 pos1 = vec2(eye1X, eye1Y) * aspect;\n    vec2 pos2 = vec2(eye2X, eye2Y) * aspect;\n    vec2 pos3 = vec2(eye3X, eye3Y) * aspect;\n\n    float d1 = length(uvAspect - pos1);\n    float d2 = length(uvAspect - pos2);\n    float d3 = length(uvAspect - pos3);\n\n    float d = min(min(d1, d2), d3);\n    vec2 activePos = pos1;\n    float eyeIndex = 1.0;\n    if (d == d2) { activePos = pos2; eyeIndex = 2.0; }\n    if (d == d3) { activePos = pos3; eyeIndex = 3.0; }\n\n    vec2 eyeUV = (uvAspect - activePos) / eyeRadius;\n    float r = length(eyeUV);\n    \n    // Animation Logic\n    float speed = epilepsyMode ? 30.0 : lookAroundSpeed;\n    float t = time * speed;\n    float f_t = floor(t);\n    float fract_t = fract(t);\n    float fr_t = epilepsyMode ? 0.0 : smoothstep(0.8, 1.0, fract_t);\n    \n    // Eye 1 and 2 are in sync, Eye 3 is independent\n    float seedOffset = independentEyes ? (eyeIndex == 3.0 ? 3.0 : 1.0) * 13.37 : 0.0;\n    \n    float randX1 = mix(0.2, 0.8, node_rand(vec2(f_t, 1.0 + seedOffset)));\n    float randX2 = mix(0.2, 0.8, node_rand(vec2(f_t + 1.0, 1.0 + seedOffset)));\n    float animX = mix(randX1, randX2, fr_t);\n    \n    float randY1 = mix(0.2, 0.8, node_rand(vec2(f_t, 2.0 + seedOffset)));\n    float randY2 = mix(0.2, 0.8, node_rand(vec2(f_t + 1.0, 2.0 + seedOffset)));\n    float animY = mix(randY1, randY2, fr_t);\n    \n    float finalTargetX = lookAround ? animX : targetX;\n    float finalTargetY = lookAround ? animY : targetY;\n\n    vec3 target3D = vec3(finalTargetX * aspect.x, finalTargetY, targetZ);\n    vec3 eye3D = vec3(activePos, 0.0);\n    vec3 lookDir = normalize(target3D - eye3D);\n    vec2 lookOffset = lookDir.xy * 0.6;\n\n    vec2 irisUV = eyeUV - lookOffset;\n    float r_iris = length(irisUV);\n    float a_iris = atan(irisUV.y, irisUV.x);\n\n    float z = sqrt(max(1.0 - r * r, 0.0));\n    vec3 N = normalize(vec3(eyeUV.x, eyeUV.y, z));\n    vec3 L = normalize(vec3(0.5, 0.5, 1.0));\n    \n    float diff = (0.4 + 0.6 * max(dot(N, L), 0.0)) * lightIntensity;\n    vec3 V = vec3(0.0, 0.0, 1.0);\n    vec3 H = normalize(L + V);\n    float spec = pow(max(dot(N, H), 0.0), 16.0) * lightIntensity * 0.15;\n\n    vec3 scleraColor = mix(vec3(0.85, 0.82, 0.82), vec3(0.6, 0.2, 0.2), smoothstep(0.6, 1.0, r));\n\n    float noiseVal = node_noise(vec2(a_iris * 5.0, r_iris * 10.0));\n    float striation = sin(a_iris * 30.0 + noiseVal * 5.0) * 0.5 + 0.5;\n    vec3 irisTex = mix(irisColor * 0.3, irisColor * 0.9, striation * noiseVal);\n    irisTex *= smoothstep(irisSize, irisSize - 0.1, r_iris); \n    \n    vec3 eyeColor = mix(scleraColor, irisTex, 1.0 - smoothstep(irisSize - 0.02, irisSize, r_iris));\n\n    float dynamicPupil = pupilSize + sin(time * 2.0) * 0.02;\n    eyeColor = mix(eyeColor, vec3(0.0), 1.0 - smoothstep(dynamicPupil - 0.02, dynamicPupil, r_iris));\n\n    eyeColor = eyeColor * diff + vec3(spec) * smoothstep(0.95, 0.85, r);\n\n    // 3D Blink Logic - Timed with saccade (movement)\n    vec3 finalEyeColor = eyeColor;\n    float finalAlphaMask = (r > 1.0) ? 0.0 : 1.0 - smoothstep(0.85, 0.95, r);\n\n    if (enableBlink) {\n        // Blink happens right as the eye starts moving (0.75 to 1.0 phase)\n        float bAmount = epilepsyMode ? 0.0 : (smoothstep(0.75, 0.85, fract_t) - smoothstep(0.85, 1.0, fract_t));\n        \n        float topLid = mix(1.2, -0.1, bAmount);\n        float bottomLid = mix(-1.2, 0.1, bAmount);\n        float lidMask = smoothstep(topLid - 0.15, topLid + 0.05, eyeUV.y) + (1.0 - smoothstep(bottomLid - 0.05, bottomLid + 0.15, eyeUV.y));\n        lidMask = clamp(lidMask, 0.0, 1.0);\n        \n        if (lidMask > 0.0) {\n            float lidRadius = 1.05; // Slightly larger than eyeball\n            float z_lid = sqrt(max(lidRadius * lidRadius - r * r, 0.0));\n            vec3 N_lid = normalize(vec3(eyeUV.x, eyeUV.y, z_lid));\n            \n            float diff_lid = (0.4 + 0.6 * max(dot(N_lid, L), 0.0)) * lightIntensity;\n            float spec_lid = pow(max(dot(N_lid, H), 0.0), 16.0) * lightIntensity * 0.15;\n            \n            vec3 shadedBlink = blinkColor * diff_lid + vec3(spec_lid) * smoothstep(lidRadius, lidRadius - 0.1, r);\n            finalEyeColor = mix(eyeColor, shadedBlink, lidMask);\n            \n            float lidAlpha = (r > lidRadius) ? 0.0 : 1.0 - smoothstep(lidRadius - 0.1, lidRadius, r);\n            finalAlphaMask = mix(finalAlphaMask, lidAlpha, lidMask);\n        }\n    }\n    \n    // Make the green areas black, then overlay the eyes\n    vec3 bg = mix(source.rgb, vec3(0.0), mask);\n    vec3 finalColor = mix(bg, finalEyeColor, mask * finalAlphaMask);\n\n    return vec4(finalColor, source.a);\n}",
