    code: "// NAME: Alien Reptile Eyes\nuniform float greenThreshold; // @min -0.5 @max 0.5 @default 0.05\nuniform vec3 irisColor; // @default 0.9,0.7,0.1\nuniform float pupilSize; // @min 0.05 @max 0.5 @default 0.15\nuniform float irisSize; // @min 0.1 @max 0.8 @default 0.50\nuniform float lightIntensity; // @min 0.0 @max 3.0 @default 1.17\n\nuniform float eye1X; // @min -0.5 @max 1.5 @default 0.59\nuniform float eye1Y; // @min -0.5 @max 1.5 @default 0.44\nuniform float eye2X; // @min -0.5 @max 1.5 @default 0.42\nuniform float eye2Y; // @min -0.5 @max 1.5 @default 0.44\nuniform float eye3X; // @min -0.5 @max 1.5 @default 0.50\nuniform float eye3Y; // @min -0.5 @max 1.5 @default 0.26\n\nuniform bool lookAround; // @default true\nuniform float lookAroundSpeed; // @min 0.1 @max 5.0 @default 0.74\nuniform bool epilepsyMode; // @default false\nuniform bool independentEyes; // @default false\n\nuniform float targetX; // @min -1.0 @max 2.0 @default 1.01\nuniform float targetY; // @min -2.0 @max 2.0 @default -1.12\nuniform float targetZ; // @min 0.1 @max 5.0 @default 0.50\nuniform float eyeRadius; // @min 0.01 @max 0.5 @default 0.06\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n\n    float greenness = source.g - max(source.r, source.b);\n    float mask = smoothstep(greenThreshold, greenThreshold + 0.1, greenness);\n\n    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);\n    vec2 uvAspect = uv * aspect;\n\n    vec2 pos1 = vec2(eye1X, eye1Y) * aspect;\n    vec2 pos2 = vec2(eye2X, eye2Y) * aspect;\n    vec2 pos3 = vec2(eye3X, eye3Y) * aspect;\n\n    float d1 = length(uvAspect - pos1);\n    float d2 = length(uvAspect - pos2);\n    float d3 = length(uvAspect - pos3);\n\n    float d = min(min(d1, d2), d3);\n    vec2 activePos = pos1;\n    float eyeIndex = 1.0;\n    if (d == d2) { activePos = pos2; eyeIndex = 2.0; }\n    if (d == d3) { activePos = pos3; eyeIndex = 3.0; }\n\n    vec2 eyeUV = (uvAspect - activePos) / eyeRadius;\n    float r = length(eyeUV);\n    \n    // Animation Logic\n    float speed = epilepsyMode ? 30.0 : lookAroundSpeed;\n    float t = time * speed;\n    float f_t = floor(t);\n    float fr_t = epilepsyMode ? 0.0 : smoothstep(0.8, 1.0, fract(t));\n    \n    // Eye 1 and 2 are in sync, Eye 3 is independent\n    float seedOffset = independentEyes ? (eyeIndex == 3.0 ? 3.0 : 1.0) * 13.37 : 0.0;\n    \n    float randX1 = mix(0.23, 0.9, node_rand(vec2(f_t, 1.0 + seedOffset)));\n    float randX2 = mix(0.23, 0.9, node_rand(vec2(f_t + 1.0, 1.0 + seedOffset)));\n    float animX = mix(randX1, randX2, fr_t);\n    \n    float randY1 = mix(0.45, 0.65, node_rand(vec2(f_t, 2.0 + seedOffset)));\n    float randY2 = mix(0.45, 0.65, node_rand(vec2(f_t + 1.0, 2.0 + seedOffset)));\n    float animY = mix(randY1, randY2, fr_t);\n    \n    float finalTargetX = lookAround ? animX : targetX;\n    float finalTargetY = lookAround ? animY : targetY;\n\n    vec3 target3D = vec3(finalTargetX * aspect.x, finalTargetY, targetZ);\n    vec3 eye3D = vec3(activePos, 0.0);\n    vec3 lookDir = normalize(target3D - eye3D);\n    vec2 lookOffset = lookDir.xy * 0.6;\n\n    vec2 irisUV = eyeUV - lookOffset;\n    float r_iris = length(irisUV);\n    float a_iris = atan(irisUV.y, irisUV.x);\n\n    float z = sqrt(max(1.0 - r * r, 0.0));\n    vec3 N = normalize(vec3(eyeUV.x, eyeUV.y, z));\n    vec3 L = normalize(vec3(0.5, 0.5, 1.0));\n    \n    float diff = (0.4 + 0.6 * max(dot(N, L), 0.0)) * lightIntensity;\n    vec3 V = vec3(0.0, 0.0, 1.0);\n    vec3 H = normalize(L + V);\n    float spec = pow(max(dot(N, H), 0.0), 16.0) * lightIntensity * 0.15;\n\n    // Darker, yellowish sclera for alien look\n    vec3 scleraColor = mix(vec3(0.8, 0.9, 0.4), vec3(0.2, 0.3, 0.1), smoothstep(0.4, 1.0, r));\n\n    float noiseVal = node_noise(vec2(a_iris * 8.0, r_iris * 15.0));\n    float striation = sin(a_iris * 40.0 + noiseVal * 10.0) * 0.5 + 0.5;\n    vec3 irisTex = mix(irisColor * 0.2, irisColor * 1.2, striation * noiseVal);\n    irisTex *= smoothstep(irisSize, irisSize - 0.1, r_iris); \n    \n    vec3 eyeColor = mix(scleraColor, irisTex, 1.0 - smoothstep(irisSize - 0.02, irisSize, r_iris));\n\n    // Reptile slit pupil\n    float dynamicPupil = pupilSize + sin(time * 2.0) * 0.02;\n    float pupilDist = length(vec2(irisUV.x * 4.5, irisUV.y));\n    eyeColor = mix(eyeColor, vec3(0.0), 1.0 - smoothstep(dynamicPupil - 0.02, dynamicPupil, pupilDist));\n\n    eyeColor = eyeColor * diff + vec3(spec) * smoothstep(0.95, 0.85, r);\n\n    float eyeballMask = (r > 1.0) ? 0.0 : 1.0 - smoothstep(0.85, 0.95, r);\n    \n    vec3 bg = mix(source.rgb, vec3(0.0), mask);\n    vec3 finalColor = mix(bg, eyeColor, mask * eyeballMask);\n\n    return vec4(finalColor, source.a);\n}",
