    code: "// NAME: Radial Dots Zoom Center\nuniform float scale; // @min 5.0 @max 100.0 @default 25.0\nuniform float centerScale; // @min 0.0 @max 10.0 @default 2.0\nuniform float thickness; // @min 0.01 @max 1.0 @default 0.6\nuniform float speed; // @min 0.0 @max 5.0 @default 1.0\nuniform float zoomSpeed; // @min 0.0 @max 5.0 @default 1.0\nuniform float zoomCenterX; // @min 0.0 @max 1.0 @default 0.5\nuniform float zoomCenterY; // @min 0.0 @max 1.0 @default 0.5\nuniform float palette; // @min 0.0 @max 1.0 @default 0.5\nuniform float morphAmount; // @min 0.0 @max 1.0 @default 0.3\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float mandalaGrid; // @min 1.0 @max 10.0 @default 2.0\nuniform float glow; // @min 0.0 @max 5.0 @default 2.5\nuniform float waveSpeed; // @min 0.0 @max 10.0 @default 3.0\nuniform float waveFreq; // @min 0.0 @max 20.0 @default 10.0\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 originalSource = texture2D(tex, uv);\n    \n    // Calculate intensity of the pure original image for the threshold\n    float origIntensity = dot(originalSource.rgb, vec3(0.299, 0.587, 0.114));\n    \n    // Apply threshold based on the original image's black areas, showing the original image\n    if (origIntensity <= threshold) {\n        return originalSource;\n    }\n\n    // Despeckle filter to remove isolated white/black pixels\n    vec2 px = 1.0 / resolution;\n    vec4 source = originalSource;\n    vec4 n_tex = texture2D(tex, uv + vec2(0.0, px.y));\n    vec4 s_tex = texture2D(tex, uv + vec2(0.0, -px.y));\n    vec4 e_tex = texture2D(tex, uv + vec2(px.x, 0.0));\n    vec4 w_tex = texture2D(tex, uv + vec2(-px.x, 0.0));\n    \n    vec4 minN = min(min(n_tex, s_tex), min(e_tex, w_tex));\n    vec4 maxN = max(max(n_tex, s_tex), max(e_tex, w_tex));\n    source = clamp(source, minN, maxN);\n\n    // Calculate intensity of the INVERTED image to keep the exact same morph shape\n    vec3 invertedRGB = 1.0 - source.rgb;\n    float morphIntensity = dot(invertedRGB, vec3(0.299, 0.587, 0.114));\n    \n    vec2 distortedUV = uv;\n    distortedUV.y -= morphIntensity * morphAmount;\n    distortedUV.x += (uv.x - 0.5) * 2.0 * morphIntensity * morphAmount * 0.2;\n    \n    // Apply custom zoom center\n    vec2 p = distortedUV - vec2(zoomCenterX, zoomCenterY);\n    p.x *= resolution.x / resolution.y;\n    \n    // Artifact prevention: clamp radius to avoid log(0)\n    float r = max(length(p), 0.001);\n    float a = atan(p.y, p.x);\n    float logR = log(r) - time * zoomSpeed;\n    \n    // Ensure seamless angular wrapping\n    float gridInt = max(1.0, floor(mandalaGrid));\n    vec2 baseUV = vec2((a / 6.2831853) * gridInt, logR * centerScale);\n    \n    vec2 scaledUV = baseUV * scale;\n    vec2 grid = fract(scaledUV) - 0.5;\n    vec2 cellId = floor(scaledUV);\n    \n    // Apply oval morphing with upward wave animation\n    float wave = sin(uv.y * waveFreq - time * waveSpeed) * 0.5 + 0.5;\n    float animatedMorph = mix(-0.2, 0.5, wave);\n    vec2 aspect = vec2(1.0 - animatedMorph, 1.0 + animatedMorph);\n    float dist = length(grid * aspect);\n    \n    // Antialiasing: dynamic smoothstep based on radius to prevent moire/artifacts\n    float aa = 0.02 + 0.1 * smoothstep(0.5, 0.0, r);\n    float pattern = smoothstep(thickness + aa, thickness - aa, dist);\n    float glowMask = smoothstep(thickness + 0.4, 0.0, dist);\n    \n    // Radial color animation from the center of each dot\n    float noiseVal = node_noise(cellId * 0.15);\n    float radialMix = sin(dist * 25.0 - time * speed * 8.0 + noiseVal * 6.28) * 0.5 + 0.5;\n    \n    // Cosine based palette using the slider\n    vec3 dotColor = 0.5 + 0.5 * cos(6.28318 * (radialMix + palette + vec3(0.0, 0.33, 0.67)));\n    \n    // Reduce normal image luminosity by 80%\n    vec3 baseImg = source.rgb * 0.2;\n    \n    // Mix core dot and add intense glow\n    vec3 col = mix(baseImg, dotColor * 1.5, pattern * morphIntensity);\n    col += dotColor * glowMask * morphIntensity * glow;\n    \n    return vec4(col, source.a);\n}",
