    code: "// NAME: Flow Diffusion Dots\nuniform float gridScale; // @min 1.0 @max 50.0 @default 20.0\nuniform float moveSpeed; // @min 0.0 @max 5.0 @default 1.0\nuniform float depthAmount; // @min 0.0 @max 1.0 @default 0.15\nuniform float dotSize; // @min 0.01 @max 0.5 @default 0.25\nuniform float centerScale; // @min -2.0 @max 2.0 @default 1.0\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.2\nuniform float symmetryX; // @min 0.400 @max 0.600 @default 0.500\nuniform float dotStretch; // @min 0.1 @max 5.0 @default 1.0\nuniform float flowScale; // @min 0.5 @max 10.0 @default 3.0\nuniform float flowSpeed; // @min 0.0 @max 5.0 @default 1.0\nuniform vec3 bgColor; // @default 0.0,0.0,0.0\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    // Sample input texture to use as a depth/displacement map\n    vec4 texColor = texture2D(tex, uv);\n    float depth = dot(texColor.rgb, vec3(0.299, 0.587, 0.114)); // Calculate luminance\n\n    // Hide pixels below the threshold\n    if (depth < threshold) {\n        return vec4(0.0);\n    }\n\n    // Calculate symmetrical depth displacement pushing outward from the custom center\n    vec2 centerDir = uv - vec2(symmetryX, 0.5);\n    vec2 depthDisp = centerDir * depth * depthAmount * 2.0;\n\n    // Mirror horizontal movement based on which side of the symmetry axis we are on\n    float dirX = sign(centerDir.x);\n    \n    // Linear movement up and outward\n    vec2 move = vec2(-time * moveSpeed * 0.2 * dirX, -time * moveSpeed * 0.2);\n\n    // Displace the UVs using the linear movement and the symmetrical image depth\n    vec2 distortedUV = uv + move + depthDisp;\n\n    // Local coordinates for grid cells (centered at intersections)\n    vec2 localUV = fract(distortedUV * gridScale + 0.5) - 0.5;\n    \n    // Apply stretch to the dots (stretching along the Y axis)\n    localUV.y /= dotStretch;\n    \n    float dist = length(localUV);\n\n    // Base background color\n    vec3 finalColor = mix(bgColor, texColor.rgb, 0.3);\n\n    // Color animation growing from the center of EACH individual dot\n    float wave = dist * 30.0 - time * 8.0;\n    vec3 dotColor = 0.5 + 0.5 * cos(wave + vec3(0.0, 1.2, 2.4));\n\n    // Flow diffusion calculation using domain warping\n    vec2 flowBaseUV = uv * flowScale;\n    vec2 q = vec2(\n        node_noise(flowBaseUV + time * flowSpeed * 0.5),\n        node_noise(flowBaseUV + vec2(5.2, 1.3) - time * flowSpeed * 0.5)\n    );\n    float flow = node_noise(flowBaseUV * 2.0 + q * 4.0);\n    \n    // Map flow to a positive multiplier\n    float flowMod = flow * 0.5 + 0.5;\n    \n    // Modify the dot size based on the flow diffusion\n    float currentDotSize = max(0.001, dotSize * flowMod * centerScale * 2.0);\n\n    // Smoothly blend the 2D dot over the background\n    float edge = smoothstep(currentDotSize, currentDotSize - 0.02, dist);\n    finalColor = mix(finalColor, dotColor, edge);\n\n    return vec4(finalColor, texColor.a);\n}",
