 // Stretch the coordinates based on the depth\n    rotatedUV.x *= 1.0 / (1.0 + depth * stretchAmount);\n    \n    // Use sine waves to create continuous repeating patterns without hard grid borders\n    vec2 localUV = sin(rotatedUV * gridScale * 3.14159) * 0.5;\n    float dist = length(localUV);\n\n    // Base background color\n    vec3 finalColor = mix(bgColor, texColor.rgb, 0.3);\n\n    // Color animation growing from the center of EACH individual line\n    float wave = dist * 20.0 - time * colorSpeed;\n    vec3 dotColor = (0.5 + 0.5 * cos(wave + vec3(0.0, 1.2, 2.4))) * animColor;\n    \n    // Multiply the animated color by the underlying image color\n    dotColor *= texColor.rgb * 2.0;\n\n    // Calculate distance from the center of the screen\n    float centerDist = length(centerDir);\n    \n    // Modify the line thickness based on the distance from the center\n    float currentDotSize = max(0.001, dotSize * (1.0 - centerDist * centerScale));\n\n    // Use a wider, dynamic smoothstep edge to heavily reduce pixelation/aliasing\n    float edgeWidth = 0.04 + currentDotSize * 0.2;\n    float edge = smoothstep(currentDotSize, currentDotSize - edgeWidth, dist);\n    \n    finalColor = mix(finalColor, dotColor, edge);\n\n    return vec4(finalColor, texColor.a * alpha);\n}",
