    code: "// NAME: Wobbly Depth Lines\nuniform float gridScale; // @min 1.0 @max 50.0 @default 20.0\nuniform float morphSpeed; // @min 0.0 @max 5.0 @default 1.0\nuniform float depthAmount; // @min 0.0 @max 1.0 @default 0.15\nuniform float dotSize; // @min 0.01 @max 0.5 @default 0.25\nuniform float centerScale; // @min -2.0 @max 2.0 @default 1.0\nuniform float stretchAmount; // @min 1.0 @max 30.0 @default 15.0\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.2\nuniform vec3 bgColor; // @default 0.0,0.0,0.0\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    // Sample input texture to use as a depth/displacement map\n    vec4 texColor = texture2D(tex, uv);\n    float depth = dot(texColor.rgb, vec3(0.299, 0.587, 0.114)); // Calculate luminance\n\n    // Hide pixels below the threshold\n    if (depth < threshold) {\n        return vec4(0.0);\n    }\n\n    // Create a morphing effect using sine waves over time\n    vec2 morph = vec2(\n        sin(time * morphSpeed + uv.y * 8.0),\n        cos(time * morphSpeed + uv.x * 8.0)\n    ) * 0.03;\n\n    // Calculate symmetrical depth displacement pushing outward from the center\n    vec2 centerDir = uv - 0.5;\n    vec2 depthDisp = centerDir * depth * depthAmount * 2.0;\n\n    // Displace the UVs using both the morphing and the symmetrical image depth\n    vec2 distortedUV = uv + morph + depthDisp;\n\n    // Local coordinates for grid cells (centered at intersections)\n    vec2 localUV = fract(distortedUV * gridScale + 0.5) - 0.5;\n    \n    // Create a wobbly rotation angle based on depth and time\n    float angle = depth * 6.28 + sin(time * morphSpeed + uv.x * 10.0 + uv.y * 10.0) * 1.5;\n    float s = sin(angle);\n    float c = cos(angle);\n    \n    // Rotate local coordinates\n    localUV = mat2(c, -s, s, c) * localUV;\n    \n    // Stretch the dots into long lines based on the depth\n    localUV.x *= 1.0 / (1.0 + depth * stretchAmount);\n    \n    float dist = length(localUV);\n\n    // Base background color\n    vec3 finalColor = mix(bgColor, texColor.rgb, 0.3);\n\n    // Color animation growing from the center of EACH individual line\n    float wave = dist * 30.0 - time * 8.0;\n    vec3 dotColor = 0.5 + 0.5 * cos(wave + vec3(0.0, 1.2, 2.4));\n    \n    // Multiply the animated color by the underlying image color\n    dotColor *= texColor.rgb * 2.0;\n\n    // Calculate distance from the center of the screen\n    float centerDist = length(centerDir);\n    \n    // Modify the line thickness based on the distance from the center\n    float currentDotSize = max(0.001, dotSize * (1.0 - centerDist * centerScale));\n\n    // Smoothly blend the wobbly line over the background\n    float edge = smoothstep(currentDotSize, currentDotSize - 0.02, dist);\n    finalColor = mix(finalColor, dotColor, edge);\n\n    return vec4(finalColor, texColor.a);\n}",
