    code: "// NAME: LSD Hexagon Pulse\nuniform float gridScale; // @min 1.0 @max 50.0 @default 25.0\nuniform float morphSpeed; // @min 0.0 @max 5.0 @default 1.0\nuniform float depthAmount; // @min 0.0 @max 1.0 @default 0.15\nuniform float hexSize; // @min 0.01 @max 0.5 @default 0.4\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.2\n\nfloat hexDist(vec2 p) {\n    p = abs(p);\n    return max(dot(p, vec2(0.8660254, 0.5)), p.y);\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 texColor = texture2D(tex, uv);\n    float depth = dot(texColor.rgb, vec3(0.299, 0.587, 0.114));\n\n    if (depth < threshold) {\n        return vec4(0.0);\n    }\n\n    // Morphing effect\n    vec2 morph = vec2(\n        sin(time * morphSpeed + uv.y * 8.0),\n        cos(time * morphSpeed + uv.x * 8.0)\n    ) * 0.03;\n\n    vec2 centerDir = uv - 0.5;\n    vec2 depthDisp = centerDir * depth * depthAmount * 2.0;\n    vec2 distortedUV = uv + morph + depthDisp;\n\n    // Hexagon grid coordinates\n    vec2 r = vec2(1.0, 1.7320508);\n    vec2 h = r * 0.5;\n    vec2 scaledUV = distortedUV * gridScale;\n    vec2 a = mod(scaledUV, r) - h;\n    vec2 b = mod(scaledUV - h, r) - h;\n    vec2 localUV = dot(a, a) < dot(b, b) ? a : b;\n    vec2 id = scaledUV - localUV;\n    \n    // Wobbly rotation\n    float angle = depth * 6.28 + sin(time * morphSpeed + uv.x * 10.0 + uv.y * 10.0) * 1.5;\n    float s = sin(angle);\n    float c = cos(angle);\n    localUV = mat2(c, -s, s, c) * localUV;\n    \n    // Hexagon shape\n    float dist = hexDist(localUV);\n    float edge = smoothstep(hexSize, hexSize - 0.05, dist);\n\n    // LSD Animation: expanding outward from the center of each hexagon\n    // dist is 0.0 at center, increasing outwards. Subtracting time makes it flow outwards.\n    float wavePhase = dist * 15.0 - time * 5.0 + id.x * 0.2 + id.y * 0.3;\n    \n    // Psychedelic color palette (RGB phase shifted)\n    vec3 lsdColor = 0.5 + 0.5 * cos(wavePhase + vec3(0.0, 2.094, 4.188));\n    \n    // Add a pulsing intensity wave\n    float pulse = sin(dist * 25.0 - time * 8.0) * 0.5 + 0.5;\n    lsdColor *= (0.6 + 0.4 * pulse);\n\n    // Blend over darkened original image\n    vec3 finalColor = mix(texColor.rgb * 0.15, lsdColor, edge);\n\n    return vec4(finalColor, texColor.a);\n}",
