    code: "// NAME: Growing Reaction Diffusion\n\nuniform float scale; // @min 1.0 @max 20.0 @default 8.0\nuniform float speed; // @min 0.0 @max 2.0 @default 0.4\nuniform float thickness; // @min 0.01 @max 0.5 @default 0.15\nuniform vec3 coralColor; // @default 0.0,0.9,0.6\n\n// Pseudo-random 2D hash generator\nvec2 hash( vec2 p ) {\n    p = vec2( dot(p,vec2(127.1,311.7)), dot(p,vec2(269.5,183.3)) );\n    return -1.0 + 2.0 * fract(sin(p) * 43758.5453123);\n}\n\n// 2D Simplex-style Noise\nfloat noise( in vec2 p ) {\n    const float K1 = 0.366025404; \n    const float K2 = 0.211324865; \n    \n    vec2 i = floor( p + (p.x+p.y)*K1 );\n    vec2 a = p - i + (i.x+i.y)*K2;\n    vec2 o = (a.x>a.y) ? vec2(1.0,0.0) : vec2(0.0,1.0);\n    vec2 b = a - o + K2;\n    vec2 c = a - 1.0 + 2.0*K2;\n    \n    vec3 h = max( 0.5-vec3(dot(a,a), dot(b,b), dot(c,c) ), 0.0 );\n    vec3 n = h*h*h*h*vec3( dot(a,hash(i+0.0)), dot(b,hash(i+o)), dot(c,hash(i+1.0)));\n    return dot( n, vec3(70.0) );\n}\n\n// Fractional Brownian Motion (fBM)\nfloat fbm( vec2 p ) {\n    float f = 0.0;\n    float amp = 0.5;\n    for( int i=0; i<4; i++ ) {\n        f += amp * noise( p );\n        p *= 2.0;\n        amp *= 0.5;\n    }\n    return f;\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 statue = texture2D(tex, uv);\n    float mask = dot(statue.rgb, vec3(0.299, 0.587, 0.114));\n\n    vec2 p = uv * scale;\n    float t = time * speed;\n\n    // DOMAIN WARPING\n    float q = fbm(p - t * 0.3);\n    float r = fbm(p + q * 3.0 + t * 0.2);\n    float s = fbm(p + r * 4.0 - t * 0.4);\n\n    // THE MAZE GENERATOR (Ridged Noise)\n    float maze = abs(cos(s * 12.0));\n    float pattern = smoothstep(thickness, thickness + 0.1, maze);\n    pattern = 1.0 - pattern;\n\n    // ORGANIC GROWTH FROM TOP TO BOTTOM\n    // Loops from 1.2 down to -0.2 to ensure full coverage\n    float growthY = 1.2 - mod(t * 0.5, 1.4);\n    float edgeNoise = fbm(p + t) * 0.3;\n    float growthMask = smoothstep(growthY, growthY + 0.2, uv.y + edgeNoise);\n\n    // Apply growth mask to the pattern\n    pattern *= growthMask;\n\n    vec3 coloredPattern = coralColor * pattern;\n    vec3 finalOutput = mix(vec3(0.0), coloredPattern * (mask + 0.2), mask);\n\n    return vec4(finalOutput, statue.a);\n}",
    uniformValues: {
          "scale": 1,
          "speed": 0.22,
          "thickness": 0.1766,
          "coralColor": [
                0,
                0.9,
                0.6
          ]
    }
