    code: "// ==========================================================================\n// SINGLE-PASS REACTION-DIFFUSION FAKE (VORONOI CELLULAR BORDERS)\n// ==========================================================================\n\n// Uniforms for your VJ software\nuniform float scale; // @min 1.0 @max 50.0 @default 12.0\nuniform float speed; // @min 0.0 @max 5.0 @default 1.0\nuniform float thickness; // @min 0.01 @max 0.5 @default 0.08\nuniform vec3 color; // @default 0.0,0.9,0.6\n\n// 2D Random Seed Generator\nvec2 random2(vec2 p) {\n    return fract(sin(vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)))) * 43758.5453);\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    // Sample the Base Statue Image\n    vec4 statue = texture2D(tex, uv);\n    \n    // Extract brightness for the mask\n    float mask = dot(statue.rgb, vec3(0.299, 0.587, 0.114));\n\n    // Setup coordinate grid for Voronoi cells\n    vec2 p = uv * scale * 1.5;\n    vec2 n = floor(p);\n    vec2 f = fract(p);\n\n    float F1 = 8.0; // Distance to closest seed\n    float F2 = 8.0; // Distance to second closest seed\n\n    // Loop through surrounding grid cells to find the closest seeds\n    for (int j = -1; j <= 1; j++) {\n        for (int i = -1; i <= 1; i++) {\n            vec2 g = vec2(float(i), float(j));\n            vec2 o = random2(n + g);\n            \n            // Animate the seeds moving around\n            o = 0.5 + 0.5 * sin(time * speed + 6.2831 * o);\n            \n            vec2 r = g + o - f;\n            float d = dot(r, r); // Calculate distance\n\n            // Sort the distances to find F1 and F2\n            if(d < F1) {\n                F2 = F1;\n                F1 = d;\n            } else if(d < F2) {\n                F2 = d;\n            }\n        }\n    }\n    \n    // THE SECRET SAUCE: (F2 - F1)\n    // Subtracting the closest distance from the second closest distance \n    // isolates the exact borders between the cells, creating a uniform web!\n    float borders = F2 - F1;\n    \n    // Use smoothstep to draw sharp lines based on the thickness uniform\n    float pattern = smoothstep(thickness, thickness + 0.05, borders);\n    \n    // Invert and colorize\n    vec3 coloredPattern = color * (1.0 - pattern);\n\n    // Composition and Masking\n    vec3 finalOutput = mix(vec3(0.0), coloredPattern * (mask + 0.2), mask);\n\n    return vec4(finalOutput, statue.a);\n}",
