    group: "Imported",
    description: "Imported from shared/user project as a sculpture preset.",
    code: "// NAME: Seamless Organic Render\n\nuniform float bumpiness; // @min 0.0 @max 100.0 @default 45.0\nuniform float threshold; // @min 0.0 @max 1.0 @default 0.1\n\nuniform float breathSpeed; // @min 0.0 @max 10.0 @default 3.5\nuniform float breathIntensity; // @min 0.0 @max 2.0 @default 0.6\nuniform float breathScale; // @min 0.1 @max 5.0 @default 1.0\n\nuniform vec3 baseColor; // @default 0.01,0.01,0.02\nuniform vec3 accentColor; // @default 1.0,0.2,0.4\nuniform vec3 highlightColor; // @default 0.0,0.9,1.0\n\nfloat getBreath(vec2 uv, float time) {\n    // Using continuous UVs for noise to prevent seams\n    float n1 = node_noise(uv * breathScale);\n    float breath = sin(time * breathSpeed + n1 * 6.0) * 0.5 + 0.5;\n    return breath * breathIntensity;\n}\n\nfloat getHeight(sampler2D tex, vec2 uv, float time) {\n    // Using fract(uv) to ensure the texture wraps seamlessly without clamping\n    float shape = texture2D(tex, fract(uv)).g;\n    \n    float breath = getBreath(uv, time);\n    float mask = smoothstep(0.04, 0.18, shape);\n    float displacement = breath * mask;\n    \n    return shape + displacement;\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec2 texel = 1.0 / resolution;\n    \n    float h = getHeight(tex, uv, time);\n    \n    float hL = getHeight(tex, uv - vec2(texel.x, 0.0), time);\n    float hR = getHeight(tex, uv + vec2(texel.x, 0.0), time);\n    float hD = getHeight(tex, uv - vec2(0.0, texel.y), time);\n    float hU = getHeight(tex, uv + vec2(0.0, texel.y), time);\n    \n    vec3 normal = normalize(vec3((hL - hR) * bumpiness, (hD - hU) * bumpiness, 1.0));\n    \n    vec3 lightDir = normalize(vec3(0.5, 0.8, 1.5));\n    float diff = max(dot(normal, lightDir), 0.0);\n    \n    vec3 viewDir = vec3(0.0, 0.0, 1.0);\n    vec3 halfDir = normalize(lightDir + viewDir);\n    float spec = pow(max(dot(normal, halfDir), 0.0), 32.0);\n    \n    float structureMask = smoothstep(threshold, threshold + 0.1, h);\n    \n    vec3 color = mix(baseColor, accentColor, structureMask);\n    color = mix(color, highlightColor, pow(clamp(h, 0.0, 1.0), 4.0));\n    \n    vec3 finalLighting = color * (diff * 0.9 + 0.1) + (spec * highlightColor * structureMask);\n    finalLighting *= smoothstep(-0.2, 0.5, h);\n\n    return vec4(finalLighting, 1.0);\n}",
    uniformValues: {
          "bumpiness": 100,
          "threshold": 0.02,
          "breathSpeed": 7,
          "breathIntensity": 0.84,
          "breathScale": 4.167,
          "baseColor": [
                0,
                0,
                0
          ],
          "accentColor": [
                0,
                0.8,
                1
          ],
          "highlightColor": [
                0.8117897727272727,
                0.6959021614310293,
                0.7383942855729853
          ]
    }
