    code: "// NAME: Random Toroid Vines\n#define MAX_STEPS 100\n#define MAX_DIST 15.0\n#define SURF_DIST 0.005\n\nuniform float morphAmount; // @min 0.0 @max 2.0 @default 1.0\nuniform float trailSpeed; // @min 0.0 @max 10.0 @default 2.0\nuniform float stripFrequency; // @min 0.1 @max 20.0 @default 6.0\nuniform vec3 color1; // @default 1.0,0.1,0.4\nuniform vec3 color2; // @default 0.1,0.0,0.9\nuniform vec3 stripeColor; // @default 0.0,1.0,0.5\nuniform vec3 stripeColor2; // @default 0.8,0.0,1.0\nuniform vec3 dotColor; // @default 1.0,0.8,0.0\nuniform float dotDensity; // @min 1.0 @max 50.0 @default 24.0\nuniform float dotSize; // @min 0.0 @max 1.0 @default 0.2\n\nmat2 Rot(float a) {\n    float s = sin(a), c = cos(a);\n    return mat2(c, -s, s, c);\n}\n\nfloat GetDist(vec3 p, float time, float depth) {\n    float torusRadius = 2.5;\n    vec2 q_torus = vec2(length(p.xz) - torusRadius, p.y);\n    \n    float randTime = time * trailSpeed * 0.5 + node_noise(vec2(time * 0.5, 0.0)) * 2.0;\n    \n    vec2 uv = q_torus;\n    uv.x = abs(uv.x);\n    float t = 12.0 + randTime;\n    vec2 q = vec2(1.0, 0.0);\n    \n    float angle = atan(p.z, p.x);\n    float th = 0.4 * angle * 6.0 - 0.6 * t;\n    \n    float morphFactor = mix(1.0, depth * 2.5, (sin(time * 1.5) * 0.5 + 0.5) * morphAmount);\n    float m = 1.2 * morphFactor;\n    \n    for (int i = 0; i < 5; i++) { \n        uv -= m * q;\n        th += 0.5 * angle * 4.0 + 0.05 * t + node_noise(vec2(float(i), time * 0.5)) * 1.5;\n        uv = Rot(th) * uv;\n        uv.x = abs(uv.x);\n        m *= 0.03 * cos(8.0 * length(uv)) + 0.55;\n    }\n    \n    return 0.5 * (length(uv) - 2.0 * m);\n}\n\nfloat RayMarch(vec3 ro, vec3 rd, float time, float depth) {\n    float dO = 0.0;\n    for(int i = 0; i < MAX_STEPS; i++) {\n        vec3 p = ro + rd * dO;\n        float dS = GetDist(p, time, depth);\n        dO += dS * 0.5;\n        if(dO > MAX_DIST || abs(dS) < SURF_DIST) break;\n    }\n    return dO;\n}\n\nvec3 GetNormal(vec3 p, float time, float depth) {\n    float d = GetDist(p, time, depth);\n    vec2 e = vec2(0.01, 0.0);\n    vec3 n = d - vec3(\n        GetDist(p - e.xyy, time, depth),\n        GetDist(p - e.yxy, time, depth),\n        GetDist(p - e.yyx, time, depth));\n    return normalize(n);\n}\n\nvec3 GetRayDir(vec2 uv, vec3 p, vec3 l, float z) {\n    vec3 f = normalize(l - p);\n    vec3 r = normalize(cross(vec3(0.0, 1.0, 0.0), f));\n    vec3 u = cross(f, r);\n    vec3 c = f * z;\n    vec3 i = c + uv.x * r + uv.y * u;\n    return normalize(i);\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    \n    if (dot(source.rgb, vec3(1.0)) < 0.01) {\n        return source;\n    }\n    \n    vec2 p_uv = (uv - 0.5) * 2.0;\n    p_uv.x *= resolution.x / resolution.y;\n    p_uv.y = -p_uv.y;\n    \n    float depth = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    \n    vec3 ro = vec3(0.0, 4.0, -6.0);\n    vec3 rd = GetRayDir(p_uv, ro, vec3(0.0, 0.0, 0.0), 1.0);\n    \n    float d = RayMarch(ro, rd, time, depth);\n    \n    vec3 col = vec3(0.0);\n    if(d < MAX_DIST) {\n        vec3 p = ro + rd * d;\n        vec3 n = GetNormal(p, time, depth);\n        vec3 lightDir = normalize(vec3(1.0, 2.0, -1.0));\n        float dif = clamp(dot(n, lightDir), 0.0, 1.0);\n        \n        float angle = atan(p.z, p.x);\n        float torusAngle = atan(p.y, length(p.xz) - 2.5);\n        \n        float randOffset = node_noise(vec2(angle * 2.0, time)) * 2.0;\n        float stripeVal = sin(angle * stripFrequency * 2.0 - time * trailSpeed + torusAngle * 4.0 + randOffset);\n        float trail = smoothstep(0.3, 1.0, stripeVal);\n        \n        vec3 gradient = mix(color1, color2, sin(angle * 3.0 + time * 2.0) * 0.5 + 0.5);\n        \n        float symFactor = sin(torusAngle * 4.0 - time * 2.0) * 0.5 + 0.5;\n        vec3 stripeGrad = mix(stripeColor, stripeColor2, symFactor);\n        \n        vec3 psychColor = stripeGrad * (0.8 + 0.2 * cos(time * 3.0 + angle * 5.0));\n        vec3 baseColor = gradient * 0.3;\n        \n        col = mix(baseColor, psychColor, trail) * dif;\n        col += psychColor * trail * 0.8; \n        col += gradient * 0.2;\n        \n        float shape2Val = sin(torusAngle * 5.0 - time * trailSpeed * 1.2 + angle * 6.0 + randOffset);\n        float shape2Mask = smoothstep(0.85, 0.95, shape2Val);\n        col = mix(col, color2, shape2Mask);\n        col += color2 * shape2Mask * 1.5;\n        \n        float stripeCenter = smoothstep(0.95, 1.0, stripeVal);\n        float dotThreshold = 1.0 - dotSize;\n        float dotMask = smoothstep(dotThreshold, 1.0, sin(torusAngle * dotDensity + angle * 10.0 - time * 4.0));\n        float finalDots = stripeCenter * dotMask;\n        \n        col = mix(col, dotColor, finalDots);\n        col += dotColor * finalDots * 1.5;\n    }\n    \n    return vec4(col, source.a);\n}",
