    code: "// NAME: Looping Morph Mirrored Stripes Hex Room\nuniform float intensity; // @min 0.0 @max 1.0 @default 1.0\nuniform float speed; // @min 0.0 @max 5.0 @default 1.0\nuniform float gridScale; // @min 1.0 @max 50.0 @default 10.0\nuniform float scale; // @min 1.0 @max 20.0 @default 4.0\nuniform float stripeCount; // @min 1.0 @max 100.0 @default 30.0\nuniform float stripeIntensity; // @min 0.0 @max 1.0 @default 0.8\nuniform float morphIntensity; // @min 0.0 @max 10.0 @default 5.0\nuniform float lineWidth; // @min 0.001 @max 0.2 @default 0.05\nuniform float stripeBlend; // @min 0.0 @max 1.0 @default 0.5\nuniform float verticalStripeCount; // @min 1.0 @max 100.0 @default 20.0\nuniform float stripeCenterY; // @min 0.0 @max 1.0 @default 0.5\n\nvec3 getThermalColor(float v) {\n    vec3 c = mix(vec3(0.0, 0.0, 0.0), vec3(0.0, 0.0, 1.0), smoothstep(0.0, 0.2, v));\n    c = mix(c, vec3(0.7, 0.0, 0.7), smoothstep(0.2, 0.4, v));\n    c = mix(c, vec3(1.0, 0.0, 0.0), smoothstep(0.4, 0.6, v));\n    c = mix(c, vec3(1.0, 1.0, 0.0), smoothstep(0.6, 0.8, v));\n    return mix(c, vec3(1.0, 1.0, 1.0), smoothstep(0.8, 1.0, v));\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    float t = time * speed;\n    \n    float currentMorph = mix(2.0, morphIntensity, 0.5 + 0.5 * sin(t));\n    \n    // --- Layer 1: Thermal Radial Stripes ---\n    vec3 animatedDepth = mix(source.rgb, 1.0 - source.rgb, 0.5 + 0.5 * sin(t));\n    float depthValue = dot(animatedDepth, vec3(0.3333));\n    vec3 thermalColor = getThermalColor(depthValue);\n    \n    vec2 centeredUv = uv - vec2(0.5, stripeCenterY);\n    float radius = length(centeredUv);\n    float angle = atan(centeredUv.y, centeredUv.x);\n    float morphedAngle = angle + depthValue * currentMorph;\n    \n    float wave = abs(sin(morphedAngle * stripeCount + t * 2.0));\n    float angularWidth = lineWidth / (radius + 0.001);\n    float stripes = smoothstep(1.0 - angularWidth - stripeBlend, 1.0 - angularWidth * 0.1, wave);\n    \n    thermalColor = mix(thermalColor, thermalColor * stripes, stripeIntensity);\n    vec3 baseLayer = mix(source.rgb, thermalColor, intensity);\n    \n    // --- Layer 2: Chemical Hex Room ---\n    float depth = dot(baseLayer, vec3(0.299, 0.587, 0.114));\n    vec2 p = uv * 2.0 - 1.0;\n    \n    float zRoom = max(0.1, 1.5 - abs(p.x));\n    vec2 uvRoom = vec2(p.y / zRoom, 1.0 / zRoom) + vec2(0.0, t);\n    uvRoom += depth * 0.4 * vec2(sin(t + uvRoom.y * 2.0), cos(t + uvRoom.x * 2.0));\n    \n    // Hexagonal Grid Logic\n    vec2 hexUv = uvRoom * gridScale;\n    vec2 r = vec2(1.0, 1.7320508);\n    vec2 h = r * 0.5;\n    vec2 a = mod(hexUv, r) - h;\n    vec2 b = mod(hexUv - h, r) - h;\n    vec2 gv = dot(a, a) < dot(b, b) ? a : b;\n    \n    float hexDist = max(abs(gv.x), dot(abs(gv), normalize(r)));\n    float hexBonds = smoothstep(0.5 - lineWidth, 0.5, hexDist);\n    float atoms = smoothstep(0.15 + 0.05 * sin(t * 5.0), 0.05, length(gv));\n    float gridLine = clamp(hexBonds + atoms, 0.0, 1.0);\n    \n    float n = node_noise(uvRoom * 3.0 + t * 0.5);\n    vec3 psyGridColor = vec3(\n        sin(n * 15.0 + t * 3.0) * 0.5 + 0.5,\n        sin(n * 20.0 - t * 2.0) * 0.5 + 0.5,\n        sin(n * 25.0 + t * 4.0) * 0.5 + 0.5\n    );\n    psyGridColor *= smoothstep(0.3, 0.6, n);\n    \n    vec3 roomColor = psyGridColor * gridLine * smoothstep(0.0, 1.5, zRoom);\n    \n    float dist = abs(p.x);\n    float bandPhase = fract(dist * scale - t * 2.0);\n    float bandAlpha = smoothstep(1.0, 0.0, dist) * smoothstep(0.7, 0.9, bandPhase) * (1.0 - bandPhase);\n    vec3 bandColor = vec3(0.2, 1.0, 0.8) * bandAlpha * 3.0; \n    \n    vec3 psySource = baseLayer * vec3(\n        0.6 + 0.5 * sin(t * 4.0 + depth * 10.0),\n        0.6 + 0.5 * cos(t * 3.2 + depth * 12.0),\n        0.6 + 0.5 * sin(t * 2.8 - depth * 8.0)\n    );\n    \n    vec3 finalColor = mix(baseLayer, psySource + roomColor + bandColor, intensity);\n    \n    // Vertical Stripes: Normal / Inverted, morphed symmetrically with 3D depth and room perspective\n    float stripeDistortion = depth * currentMorph * 0.05 + (1.0 / zRoom) * 0.05;\n    float vStripe = step(0.5, fract((abs(uv.x - 0.5) + stripeDistortion) * verticalStripeCount));\n    finalColor = mix(finalColor, 1.0 - finalColor, vStripe);\n    \n    float isNotBlack = step(0.03, length(source.rgb));\n    finalColor *= isNotBlack;\n    \n    return vec4(finalColor, source.a);\n}",
