    code: "// NAME: Psytrance Thermal Stripes Room\nuniform float intensity; // @min 0.0 @max 1.0 @default 1.0\nuniform float speed; // @min 0.0 @max 5.0 @default 1.0\nuniform float gridScale; // @min 5.0 @max 100.0 @default 30.0\nuniform float scale; // @min 1.0 @max 20.0 @default 4.0\nuniform float stripeCount; // @min 1.0 @max 100.0 @default 30.0\nuniform float stripeIntensity; // @min 0.0 @max 1.0 @default 0.8\nuniform float morphIntensity; // @min 0.0 @max 10.0 @default 5.0\nuniform float lineWidth; // @min 0.001 @max 0.1 @default 0.02\nuniform float stripeBlend; // @min 0.0 @max 1.0 @default 0.5\n\nvec3 getThermalColor(float v) {\n    float t0 = smoothstep(0.0, 0.2, v);\n    float t1 = smoothstep(0.2, 0.4, v);\n    float t2 = smoothstep(0.4, 0.6, v);\n    float t3 = smoothstep(0.6, 0.8, v);\n    float t4 = smoothstep(0.8, 1.0, v);\n\n    vec3 c = mix(vec3(0.0, 0.0, 0.0), vec3(0.0, 0.0, 1.0), t0);\n    c = mix(c, vec3(0.7, 0.0, 0.7), t1);\n    c = mix(c, vec3(1.0, 0.0, 0.0), t2);\n    c = mix(c, vec3(1.0, 1.0, 0.0), t3);\n    return mix(c, vec3(1.0, 1.0, 1.0), t4);\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    float t = time * speed;\n    \n    // --- Layer 1: Thermal Radial Stripes ---\n    vec3 animatedDepth = mix(source.rgb, 1.0 - source.rgb, 0.5 + 0.5 * sin(t));\n    float depthValue = dot(animatedDepth, vec3(0.3333));\n    vec3 thermalColor = getThermalColor(depthValue);\n    \n    vec2 centeredUv = uv - 0.5;\n    float radius = length(centeredUv);\n    float angle = atan(centeredUv.y, centeredUv.x);\n    float morphedAngle = angle + depthValue * morphIntensity;\n    \n    float wave = abs(sin(morphedAngle * stripeCount + t * 2.0));\n    float angularWidth = lineWidth / (radius + 0.001);\n    float stripes = smoothstep(1.0 - angularWidth - stripeBlend, 1.0 - angularWidth * 0.1, wave);\n    \n    thermalColor = mix(thermalColor, thermalColor * stripes, stripeIntensity);\n    vec3 baseLayer = mix(source.rgb, thermalColor, intensity);\n    \n    // --- Layer 2: Psytrance Disco Room ---\n    float depth = dot(baseLayer, vec3(0.299, 0.587, 0.114));\n    vec2 p = uv * 2.0 - 1.0;\n    \n    vec3 psySource = baseLayer * vec3(\n        0.6 + 0.5 * sin(t * 4.0 + depth * 10.0),\n        0.6 + 0.5 * cos(t * 3.2 + depth * 12.0),\n        0.6 + 0.5 * sin(t * 2.8 - depth * 8.0)\n    );\n    \n    float zRoom = max(0.1, 1.5 - abs(p.x));\n    vec2 uvRoom = vec2(p.y / zRoom, 1.0 / zRoom) + vec2(0.0, t);\n    uvRoom += depth * 0.4 * vec2(sin(t + uvRoom.y * 2.0), cos(t + uvRoom.x * 2.0));\n    vec2 fGrid = fract(uvRoom * gridScale);\n    float gridLine = clamp(step(0.85, fGrid.x) + step(0.85, fGrid.y), 0.0, 1.0);\n    \n    // Grid takes the opposite color of the underlying psySource\n    vec3 combined = mix(psySource, 1.0 - psySource, gridLine * smoothstep(0.0, 1.5, zRoom));\n    \n    float dist = abs(p.x);\n    float bandPhase = fract(dist * scale - t * 2.0);\n    float bandAlpha = smoothstep(1.0, 0.0, dist) * smoothstep(0.7, 0.9, bandPhase) * (1.0 - bandPhase);\n    vec3 bandColor = vec3(1.0, 0.2, 0.8) * bandAlpha * 3.0;\n    \n    vec3 finalColor = mix(baseLayer, combined + bandColor, intensity);\n    \n    // Keep black pixels of the original image black\n    float isNotBlack = step(0.03, length(source.rgb));\n    finalColor *= isNotBlack;\n    \n    return vec4(finalColor, source.a);\n}",
