    code: "// NAME: Metallic Fractal Zones\nuniform float intensity; // @min 0.0 @max 1.0 @default 0.8\nuniform float speed; // @min 0.0 @max 2.0 @default 0.5\nuniform float blackThreshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float morphAmount; // @min 0.0 @max 5.0 @default 1.5\nuniform float zoneScale; // @min 0.0 @max 1.0 @default 0.4\nuniform float frequency; // @min 1.0 @max 30.0 @default 10.0\nuniform float sharpness; // @min 1.0 @max 10.0 @default 4.0\nuniform vec3 tint; // @default 0.9,0.95,1.0\n\nmat2 rot(float a) {\n    float c = cos(a), s = sin(a);\n    return mat2(c, -s, s, c);\n}\n\nfloat map(vec3 p, float t, float zScale) {\n    float s = 1.0;\n    vec3 offset = vec3(0.4) + zScale * vec3(sin(p.y * 2.5 + t), cos(p.z * 2.5), sin(p.x * 2.5 - t));\n    \n    for(int i = 0; i < 5; i++) {\n        p = abs(p) - offset;\n        p.xy *= rot(t * 0.5 + 0.5);\n        p.xz *= rot(t * 0.3);\n        p *= 1.65;\n        s *= 1.65;\n    }\n    return length(p) / s - 0.005;\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    \n    // Calculate luminance to act as a depth map and mask\n    float luma = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    float mask = smoothstep(blackThreshold * 0.5, blackThreshold + 0.01, luma);\n    \n    // Center and correct aspect ratio\n    vec2 p = (uv - 0.5) * 2.0;\n    p.x *= resolution.x / (resolution.y + 0.0001);\n    \n    // Morph time and camera position based on image depth (luminance)\n    float t = time * speed + luma * morphAmount;\n    vec3 ro = vec3(0.0, 0.0, -1.5 + luma * morphAmount * 0.5);\n    vec3 rd = normalize(vec3(p, 1.0));\n    \n    float d = 0.0;\n    float dist = 0.0;\n    int steps = 0;\n    vec3 pos = vec3(0.0);\n    \n    // Raymarching loop\n    for(int i = 0; i < 45; i++) {\n        pos = ro + rd * dist;\n        d = map(pos, t, zoneScale);\n        if(d < 0.001 || dist > 5.0) break;\n        dist += d;\n        steps = i;\n    }\n    \n    // Color based on time animation and position\n    vec3 dynamicColor = 0.5 + 0.5 * cos(time * speed * 2.0 + pos.xyz * 2.0 + vec3(0.0, 2.0, 4.0));\n    \n    float stepRatio = float(steps) / 45.0;\n    vec3 finalFractalColor = mix(vec3(0.05), dynamicColor, stepRatio * 2.0);\n    finalFractalColor = mix(finalFractalColor, dynamicColor * 1.5, pow(stepRatio, 2.0));\n    \n    // Add dynamic glow and depth fog\n    finalFractalColor += dynamicColor * (0.02 / (d + 0.01));\n    finalFractalColor *= exp(-dist * 0.5);\n    \n    // Base fractal blend with original texture\n    vec3 fractalBlend = finalFractalColor + source.rgb * finalFractalColor * 0.5;\n    \n    // Metallic Depth Strips logic\n    float phase = luma * frequency - time * speed * 2.0;\n    float band1 = sin(phase * 6.28318) * 0.5 + 0.5;\n    float band2 = sin(phase * 15.0 + 2.0) * 0.5 + 0.5;\n    float band3 = sin(phase * 3.0 - 1.0) * 0.5 + 0.5;\n    \n    float metallic = pow(band1 * 0.6 + band2 * 0.2 + band3 * 0.2, sharpness);\n    float highlight = smoothstep(0.7, 1.0, metallic);\n    vec3 reflectionColor = mix(vec3(0.05), tint, metallic) + highlight;\n    \n    // Combine fractal base with metallic reflections\n    vec3 metallicBlend = fractalBlend * reflectionColor * 2.0 + reflectionColor * 0.6;\n    \n    // Blend with original texture, using the mask to protect black pixels\n    vec3 finalColor = mix(source.rgb, metallicBlend, intensity * mask);\n    \n    return vec4(finalColor, source.a);\n}",
