    description: "Imported from shared/user project as a sculpture preset.",
    code: "// NAME: Psytrance Vines\nuniform float intensity; // @min 0.0 @max 1.0 @default 0.8\nuniform float speed; // @min 0.0 @max 2.0 @default 0.5\nuniform float blackThreshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float morphAmount; // @min 0.0 @max 5.0 @default 1.0\nuniform vec3 vineColor; // @default 0.5,0.0,1.0\n\nmat2 rot(float a) {\n    float c = cos(a), s = sin(a);\n    return mat2(c, -s, s, c);\n}\n\nfloat map(vec3 p, float t) {\n    float s = 1.0;\n    p.xz *= rot(p.y * 0.5 + t * 0.2);\n    for(int i = 0; i < 3; i++) {\n        p = abs(p) - 0.35;\n        p.xy *= rot(t * 0.4 + 0.2);\n        p.xz *= rot(t * 0.3);\n        p *= 1.7; s *= 1.7;\n    }\n    return length(p.xy) / s - 0.005;\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    float luma = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    float mask = smoothstep(blackThreshold * 0.5, blackThreshold + 0.01, luma);\n    \n    vec2 p = (uv - 0.5) * 2.0;\n    p.x *= resolution.x / (resolution.y + 0.0001);\n    \n    float t = time * speed + luma * morphAmount * 0.5;\n    vec3 ro = vec3(0.0, 0.0, -1.5 + luma * morphAmount * 0.25);\n    vec3 rd = normalize(vec3(p, 1.0));\n    \n    float d = 0.0, dist = 0.0;\n    for(int i = 0; i < 40; i++) {\n        d = map(ro + rd * dist, t);\n        if(d < 0.002 || dist > 4.0) break;\n        dist += d * 0.7; \n    }\n    \n    vec3 plantColor = vec3(0.0);\n    if(dist < 4.0) {\n        vec3 pos = ro + rd * dist;\n        float distFromCenter = length(pos);\n        vec3 psyColor = vineColor * 0.5 + 0.5 * cos(distFromCenter * 3.0 - time * 4.0 + vec3(0.0, 2.0, 4.0));\n        plantColor = psyColor * exp(-dist * 0.5) * 2.0;\n    }\n    \n    vec3 finalColor = mix(source.rgb, plantColor + source.rgb * plantColor, intensity * mask);\n    return vec4(finalColor, source.a);\n}",
