    code: "// NAME: Customizable Psytrance Vines\nuniform float intensity; // @min 0.0 @max 1.0 @default 0.8\nuniform float speed; // @min 0.0 @max 2.0 @default 0.5\nuniform float blackThreshold; // @min 0.0 @max 1.0 @default 0.05\nuniform float morphAmount; // @min 0.0 @max 5.0 @default 1.0\nuniform float vineThickness; // @min 0.001 @max 0.02 @default 0.005\nuniform vec3 vineColor; // @default 0.5,0.0,1.0\nuniform float pulseIntensity; // @min 0.0 @max 10.0 @default 4.5\n\nmat2 rot(float a) {\n    float c = cos(a), s = sin(a);\n    return mat2(c, -s, s, c);\n}\n\nfloat map(vec3 p, float t) {\n    float s = 1.0;\n    p.xz *= rot(p.y * 0.5 + t * 0.2);\n    for(int i = 0; i < 4; i++) {\n        p = abs(p) - 0.35;\n        p.xy *= rot(t * 0.4 + 0.2);\n        p.xz *= rot(t * 0.3);\n        p *= 1.7; s *= 1.7;\n    }\n    return length(p.xy) / s - vineThickness;\n}\n\nvec3 calcNormal(vec3 p, float t) {\n    vec2 e = vec2(0.002, 0.0);\n    return normalize(vec3(\n        map(p + e.xyy, t) - map(p - e.xyy, t),\n        map(p + e.yxy, t) - map(p - e.yxy, t),\n        map(p + e.yyx, t) - map(p - e.yyx, t)\n    ));\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    \n    // Sample neighbors slightly to blur the luma and reduce sharp pixel artifacts in the SDF\n    vec2 offset = 1.0 / resolution;\n    vec3 s1 = texture2D(tex, uv + vec2(offset.x, 0.0)).rgb;\n    vec3 s2 = texture2D(tex, uv - vec2(offset.x, 0.0)).rgb;\n    vec3 s3 = texture2D(tex, uv + vec2(0.0, offset.y)).rgb;\n    vec3 s4 = texture2D(tex, uv - vec2(0.0, offset.y)).rgb;\n    vec3 blurredSource = (source.rgb + s1 + s2 + s3 + s4) * 0.2;\n    \n    float luma = dot(blurredSource, vec3(0.299, 0.587, 0.114));\n    float mask = smoothstep(blackThreshold * 0.5, blackThreshold + 0.01, luma);\n    \n    vec2 p = (uv - 0.5) * 2.0;\n    p.x *= resolution.x / (resolution.y + 0.0001);\n    \n    // Smooth luma to prevent SDF tearing\n    float smoothLuma = smoothstep(0.0, 1.0, luma);\n    float t = time * speed + smoothLuma * morphAmount * 0.5;\n    vec3 ro = vec3(0.0, 0.0, -1.5 + smoothLuma * morphAmount * 0.25);\n    vec3 rd = normalize(vec3(p, 1.0));\n    \n    float d = 0.0, dist = 0.0;\n    int steps = 0;\n    // Increased steps and reduced step size to handle SDF distortions better\n    for(int i = 0; i < 60; i++) {\n        vec3 pos = ro + rd * dist;\n        d = map(pos, t);\n        if(d < 0.001 || dist > 5.0) break;\n        dist += d * 0.6; \n        steps = i;\n    }\n    \n    vec3 plantColor = vec3(0.0);\n    if(dist < 5.0) {\n        vec3 pos = ro + rd * dist;\n        vec3 n = calcNormal(pos, t);\n        vec3 lightDir = normalize(vec3(0.6, 0.8, -0.4));\n        \n        float diff = max(dot(n, lightDir), 0.0);\n        float spec = pow(max(dot(reflect(-lightDir, n), -rd), 0.0), 32.0);\n        float ao = clamp(1.0 - float(steps) / 60.0, 0.0, 1.0);\n        \n        float distFromCenter = length(pos);\n        float wave = distFromCenter * 2.5 - time * speed * 8.0;\n        float section = floor(wave);\n        float rnd = node_rand(vec2(section, 42.0));\n        float circleGrad = fract(wave);\n        \n        vec3 psyColor = vineColor * 0.5 + 0.5 * cos(distFromCenter * 3.0 - time * 4.0 + rnd * 6.28 + vec3(0.0, 2.0, 4.0));\n        vec3 baseColor = mix(vec3(0.1, 0.0, 0.2), psyColor, 0.85);\n        \n        float trail = pow(circleGrad, 6.0);\n        vec3 emission = psyColor * trail * pulseIntensity;\n        \n        vec3 ambient = psyColor * 0.15 * ao;\n        vec3 diffuse = baseColor * diff * 1.2;\n        vec3 specular = vec3(0.9, 1.0, 0.9) * spec;\n        \n        plantColor = ambient + diffuse + specular + emission;\n        plantColor *= exp(-dist * 0.4);\n    }\n    \n    vec3 finalColor = mix(source.rgb, plantColor + source.rgb * plantColor * 0.5, intensity * mask);\n    return vec4(finalColor, source.a);\n}",
