    description: "Imported from shared/user project as a sculpture preset.",
    code: "// NAME: Morphing Triangles\nuniform float centerX; // @min -2.0 @max 2.0 @default 0.0\nuniform float centerY; // @min -2.0 @max 2.0 @default 0.0\n\n#define PI 3.14159265359\n#define TWO_PI 6.28318530718\n\nfloat impulse(float k, float x) {\n    float h = k * x;\n    return h * exp(1.0 - h);\n}\n\nfloat plot(float dis) {\n    float blur = 0.227794;\n    float lineSize = 0.24540144;\n    return smoothstep(dis, dis + blur, 0.5) - smoothstep(lineSize + dis, lineSize + dis + blur, 0.5);\n}\n\nvec3 rgb2hsb(vec3 c) {\n    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);\n    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));\n    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));\n    float d = q.x - min(q.w, q.y);\n    float e = 1.0e-10;\n    return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);\n}\n\nvec3 hsb2rgb(vec3 c) {\n    vec3 rgb = clamp(abs(mod(c.x * 6.0 + vec3(0.0, 4.0, 2.0), 6.0) - 3.0) - 1.0, 0.0, 1.0);\n    rgb = rgb * rgb * (3.0 - 2.0 * rgb);\n    return c.z * mix(vec3(1.0), rgb, c.y);\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    float lum = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    \n    if (lum < 0.01) {\n        return source;\n    }\n\n    vec2 st = uv * 2.0 - 1.0;\n    st.x -= centerX;\n    st.y -= centerY;\n    st.x *= resolution.x / resolution.y;\n    \n    float size = 0.0240525;\n    float grid = 9.510933;\n    float morph = 5.2208757 * lum; \n    float delayAmount = 3.223359;\n    float delay2 = 6.429779;\n    float speed = 0.39144516;\n\n    vec3 colorNew = vec3(0.0);\n    float r = TWO_PI / 3.0;\n\n    for(int i = 0; i < 5; i++) {\n        float m = float(i) / 5.0;\n        vec2 st_i = st;\n        st_i.y += size * m * sin(time / 3.0);\n        float a = atan(st_i.x, st_i.y) + PI + (morph * m) + (0.03 * m * sin(time));\n        \n        float d = cos(floor(0.5 + a / r) * r - a) * length(st_i);\n        d = impulse(d, delayAmount);\n        \n        float check = delay2 * (1.0 - length(st_i));\n        vec3 color = vec3(0.0);\n        color.r = plot(fract(d * grid - check + time * speed));\n        color.g = plot(fract(d * grid - check + time * speed * 0.8));\n        color.b = plot(fract(d * grid - check + time * speed * 0.6));\n        colorNew += color * m;\n    }\n\n    vec3 hue = rgb2hsb(colorNew);\n    hue.x = 0.6;\n    hue.y = 0.5;\n    vec3 finalColor = hsb2rgb(hue) - colorNew * 0.2;\n    \n    return vec4(mix(source.rgb, finalColor, lum), source.a);\n}",
