    code: "// NAME: Luminous Tall Psychedelic Tubes\n\nuniform float speed; // @min 0.1 @max 2.0 @default 1.0\nuniform float amplitude; // @min 1.0 @max 15.0 @default 9.0\nuniform float morph; // @min 0.0 @max 5.0 @default 1.5\nuniform float stripe_freq; // @min 5.0 @max 80.0 @default 35.0\nuniform float psych_speed; // @min 0.5 @max 10.0 @default 4.0\n\nfloat round_val(float x) {\n    return floor(x + 0.5);\n}\n\nfloat map(vec3 u, float v, float t, float amp) {\n    float l = 5.0;\n    float f = 1e10;\n    \n    u.xy = vec2(atan(u.x, u.y), length(u.xy));\n    u.x += t * v * 3.141592 * 0.7;\n    \n    for (int i = 1; i <= 5; i++) {\n        float fi = float(i);\n        vec3 p = u;\n        float y = round_val((p.y - fi) / l) * l + fi;\n        p.x *= y;\n        p.x -= y * y * t * 3.141592;\n        p.x -= round_val(p.x / 6.283185) * 6.283185;\n        p.y -= y;\n        float z = cos(y * t * 6.283185) * 0.5 + 0.5;\n        f = min(f, max(length(p.xy), -p.z - z * amp) - 0.1 - z * 0.2 - p.z / 100.0);\n    }\n    return f;\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 texColor = texture2D(tex, uv);\n    float depth = (texColor.r + texColor.g + texColor.b) / 3.0;\n    \n    float t = (time * 0.003) * speed;\n    vec2 m = vec2(0.0, 0.5);\n    // Make it taller by scaling the Y aspect\n    vec2 aspect = vec2(resolution.x / resolution.y, 0.5);\n    \n    vec3 o = vec3(0.0, 0.0, -130.0);\n    \n    vec2 distorted_uv = uv + (depth - 0.5) * morph * 0.15;\n    vec3 u = normalize(vec3((distorted_uv - 0.5) * aspect, 1.0));\n    vec3 c = vec3(0.0);\n    \n    float v = -o.z / 3.0;\n    float d = 0.0;\n    float s = 0.0;\n    float z = 0.0;\n    float f = 0.0;\n    vec3 k = vec3(0.0);\n    vec3 p = vec3(0.0);\n    bool b = false;\n    \n    // Enhance 3D depth effect\n    float dynamic_amp = amplitude + (depth - 0.5) * morph * 8.0;\n    \n    for (int i = 0; i < 40; i++) {\n        p = u * d + o;\n        p.xy /= v;\n        float r = length(p.xy);\n        z = abs(1.0 - r * r);\n        b = r < 1.0;\n        if (b) z = sqrt(z);\n        p.xy /= z + 1.0;\n        p.xy -= m;\n        p.xy *= v;\n        p.xy -= cos(p.z / 8.0 + t * 300.0 + vec2(0.0, 1.5708) + z / 2.0) * 0.2;\n        \n        s = map(p, v, t, dynamic_amp);\n        \n        r = length(p.xy);\n        f = cos(round_val(r) * t * 6.283185) * 0.5 + 0.5;\n        \n        float stripe = sin(p.z * 0.15 + r * stripe_freq - time * psych_speed) * 0.5 + 0.5;\n        vec3 psych_color = cos(vec3(0.0, 2.09439, 4.18879) + stripe * 6.283185 + time * psych_speed * 0.5) * 0.5 + 0.5;\n        \n        k = cos(vec3(3.141592, 1.570796, 0.0) + (0.2 - f / 3.0 + t + p.z / 200.0) * 6.283185) * 0.5 + 0.5;\n        k = mix(k, psych_color, 0.85);\n        \n        if (b) k = 1.0 - k;\n        \n        // Increase luminosity accumulation\n        c += min(exp(s / -0.05), s)\n           * (f + 0.01)\n           * min(z, 1.0)\n           * sqrt(cos(r * 6.283185) * 0.5 + 0.5)\n           * k * k * 1.5;\n        \n        d += s * clamp(z, 0.3, 0.9);\n        if (s < 1e-3 || d > 1e3) break;\n    }\n    \n    c += texColor.rgb * vec3(0.1, 0.3, 0.5) * (1.0 - depth) * s * 0.2;\n    c += min(exp(-p.z - f * dynamic_amp) * z * k * 0.02 / max(s, 1e-5), 1.5);\n    \n    vec2 j = p.xy / v + m;\n    c /= clamp(dot(j, j) * 3.0, 0.1, 10.0);\n    \n    vec3 finalColor = mix(texColor.rgb, c, clamp(depth * (1.0 + morph * 0.5), 0.0, 1.0));\n    \n    float screen_stripe = sin((uv.x - uv.y) * stripe_freq * 0.3 + time * psych_speed) * 0.5 + 0.5;\n    vec3 screen_psych = cos(vec3(0.0, 2.09439, 4.18879) + screen_stripe * 6.283185) * 0.5 + 0.5;\n    \n    // Boost final luminosity\n    finalColor = mix(finalColor, finalColor * screen_psych * 3.0, 0.35);\n    \n    return vec4(finalColor, 1.0);\n}",
