    id: "timeline-03168de1-0a21-432f-847f-072544ccb655",
    name: "Moving Shifting Maze",
    template: "sculpture",
    group: "Imported",
    description: "Imported from shared/user project as a sculpture preset.",
    code: "// NAME: Moving Shifting Maze\nuniform float scale; // @min 5.0 @max 50.0 @default 15.0\nuniform float thickness; // @min 0.001 @max 0.1 @default 0.01\nuniform float moveSpeed; // @min 0.0 @max 2.0 @default 0.2\nuniform float pathChangeSpeed; // @min 0.0 @max 2.0 @default 0.5\nuniform float offset; // @min 0.0 @max 0.1 @default 0.015\nuniform float speed; // @min 0.1 @max 5.0 @default 1.5\nuniform float delay; // @min 0.1 @max 2.0 @default 0.5\nuniform float distortion; // @min 0.0 @max 0.5 @default 0.15\nuniform float shine; // @min 1.0 @max 5.0 @default 2.5\nuniform float depthStrength; // @min 0.0 @max 0.5 @default 0.15\nuniform float noiseScale; // @min 1.0 @max 20.0 @default 4.0\nuniform float pulseSpeed; // @min 0.1 @max 5.0 @default 2.0\nuniform float pulseWidth; // @min 0.01 @max 0.5 @default 0.1\nuniform float pulseIntensity; // @min 0.0 @max 10.0 @default 3.0\nuniform float baseDim; // @min 0.0 @max 1.0 @default 0.15\nuniform float darkNoiseScale; // @min 1.0 @max 20.0 @default 8.0\nuniform float darkNoiseSpeed; // @min 0.1 @max 5.0 @default 1.2\nuniform float darkNoiseStrength; // @min 0.0 @max 1.0 @default 0.85\n\nvec2 rotate(vec2 v, float a) {\n    float s = sin(a);\n    float c = cos(a);\n    return vec2(v.x * c - v.y * s, v.x * s + v.y * c);\n}\n\nfloat getMaze(vec2 uv, vec2 baseUv, float s, float t, float localTime, float nScale) {\n    vec2 scrolledUv = uv + vec2(localTime * moveSpeed, localTime * moveSpeed * 0.7);\n    vec2 id = floor(scrolledUv * s);\n    vec2 gv = fract(scrolledUv * s) - 0.5;\n    \n    float n = node_noise(id * 0.3 + localTime * pathChangeSpeed);\n    \n    if (n < 0.5) gv.x *= -1.0;\n    float d = abs(gv.x - gv.y);\n    \n    float flow = sin(localTime * speed + uv.x * 8.0 + uv.y * 8.0) * 0.5 + 0.5;\n    float maskNoise = node_noise(baseUv * nScale + localTime * 0.6);\n    float activeMask = mix(0.3, 1.0, maskNoise);\n    \n    float core = smoothstep(t, t * 0.1, d);\n    float glow = smoothstep(t * 6.0, 0.0, d) * 0.5;\n    \n    return (core + glow) * (0.2 + 0.8 * flow) * activeMask;\n}\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    \n    if (length(source.rgb) < 0.05) {\n        return source;\n    }\n    \n    float depth = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    vec2 depthUv = uv + (uv - 0.5) * depth * depthStrength;\n    \n    vec2 warpedUv = depthUv;\n    warpedUv.x += node_noise(depthUv * 4.0 + time * 0.4) * distortion;\n    warpedUv.y += node_noise(depthUv * 4.0 - time * 0.5 + 10.0) * distortion;\n    \n    float swirlAngle = 0.785398 + sin(time * 0.3 + length(depthUv - 0.5) * 4.0) * 0.4;\n    vec2 mazeUv = rotate(warpedUv - 0.5, swirlAngle) + 0.5;\n    \n    float m_red = getMaze(mazeUv + vec2(offset, offset), depthUv, scale, thickness, time, noiseScale);\n    float m_green = getMaze(mazeUv + vec2(-offset, offset), depthUv, scale, thickness, time - delay, noiseScale);\n    float m_blue = getMaze(mazeUv + vec2(offset, -offset), depthUv, scale, thickness, time - delay * 2.0, noiseScale);\n    float m_yellow = getMaze(mazeUv + vec2(-offset, -offset), depthUv, scale, thickness, time - delay * 3.0, noiseScale);\n    \n    vec3 finalColor = vec3(0.0);\n    finalColor += vec3(1.0, 0.05, 0.2) * m_red * shine;\n    finalColor += vec3(0.05, 1.0, 0.2) * m_green * shine;\n    finalColor += vec3(0.1, 0.3, 1.0) * m_blue * shine;\n    finalColor += vec3(1.0, 0.9, 0.05) * m_yellow * shine;\n    \n    float scan = fract(mazeUv.x + mazeUv.y - time * pulseSpeed);\n    float highlight = smoothstep(pulseWidth, 0.0, abs(scan - 0.5));\n    \n    finalColor = mix(finalColor * baseDim, finalColor * (1.0 + pulseIntensity), highlight);\n    \n    float darkFlow = node_noise(depthUv * darkNoiseScale + vec2(time * darkNoiseSpeed, -time * darkNoiseSpeed * 0.5));\n    darkFlow = smoothstep(0.2, 0.8, darkFlow);\n    finalColor *= mix(1.0, darkFlow, darkNoiseStrength);\n    \n    vec3 outColor = source.rgb * 0.15 + finalColor;\n    \n    return vec4(outColor, source.a);\n}",
