    description: "Imported from shared/user project as a sculpture preset.",
    code: "// NAME: Psychedelic Contrast VJ Eyes\nuniform float levels; // @min 2.0 @max 8.0 @default 4.0\nuniform float threshold; // @min 0.45 @max 0.95 @default 0.8\nuniform vec3 lineColor; // @default 0.10,0.12,0.16\nuniform float contrast; // @min 0.0 @max 1.0 @default 0.5\nuniform float psychContrast; // @min 0.0 @max 1.0 @default 0.5\nuniform float chrome; // @min 0.0 @max 1.0 @default 0.5\nuniform float luminosityshine; // @min 0.0 @max 1.0 @default 0.5\nuniform float linetreshold; // @min 0.0 @max 1.0 @default 0.5\nuniform float linevelocity; // @min 0.0 @max 1.0 @default 0.5\nuniform float linetint; // @min 0.0 @max 1.0 @default 0.5\n\nuniform float tolerance; // @min -0.5 @max 1.0 @default 0.05\nuniform float pupilSize; // @min 0.0 @max 0.5 @default 0.10\nuniform float gridScale; // @min 1.0 @max 50.0 @default 12.0\nuniform float moveSpeed; // @min 0.0 @max 5.0 @default 2.0\nuniform float amountofmovement; // @min 0.0 @max 1.0 @default 0.5\nuniform vec3 pupilColor; // @default 0.0,0.0,0.0\nuniform vec3 irisColor; // @default 0.2,0.5,0.8\nuniform float gridposition; // @min 0.0 @max 1.0 @default 0.5\n\nvec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {\n    vec4 source = texture2D(tex, uv);\n    float lum = dot(source.rgb, vec3(0.299, 0.587, 0.114));\n    \n    // Psychedelic VJ Contrast Modulation\n    float wave = sin(time * 3.0 + uv.y * 12.0 + cos(time + uv.x * 8.0)) * 0.5 + 0.5;\n    float dynamicContrast = (contrast * 2.0) + (wave * psychContrast * 2.0) - (psychContrast * 0.5);\n    \n    // Apply dynamic contrast\n    lum = clamp((lum - 0.5) * dynamicContrast + 0.5, 0.0, 1.0);\n    \n    // Subtle RGB split based on contrast wave for VJ feel\n    vec3 sourceShifted = source.rgb;\n    sourceShifted.r = texture2D(tex, uv + vec2(wave * 0.01 * psychContrast, 0.0)).r;\n    sourceShifted.b = texture2D(tex, uv - vec2(wave * 0.01 * psychContrast, 0.0)).b;\n    \n    float noisePulse = node_noise(uv * 3.0 + vec2(time * 0.12, -time * 0.09));\n    float animatedLevels = max(2.0, levels + sin(time * 0.8 + noisePulse * 6.28318) * 0.35);\n    float poster = floor(lum * animatedLevels) / max(animatedLevels - 1.0, 1.0);\n    float ink = 1.0 - smoothstep(threshold - 0.16, threshold, lum + (noisePulse - 0.5) * 0.04);\n\n    vec3 plate = vec3(poster) * (0.92 + 0.08 * sin(time * 0.9 + uv.y * 8.0));\n    \n    // Apply chrome effect\n    vec3 chromeColor = 0.5 + 0.5 * cos(time * 1.5 + poster * 5.0 + vec3(0.0, 2.0, 4.0));\n    plate = mix(plate, plate * chromeColor * 2.0, chrome);\n\n    vec3 animatedLine = clamp(\n        lineColor + vec3(\n            sin(time * 0.8 + uv.x * 5.0),\n            sin(time * 1.0 + uv.y * 6.0 + 2.0),\n            sin(time * 1.2 + uv.x * 4.0 + 4.0)\n        ) * 0.05,\n        0.0,\n        1.0\n    );\n    \n    vec3 result = mix(plate, animatedLine, ink);\n    \n    // Apply luminosity shine\n    float shine = pow(max(lum, 0.0), 3.0) * luminosityshine * 1.5;\n    result = clamp(",
